import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Student, ExamSession, StudentStatus } from '../types';

interface ExamRoomProps {
  student: Student;
  students: Student[]; 
  session: ExamSession;
  onFinish: () => void;
}

const ExamRoom: React.FC<ExamRoomProps> = ({ student, students, session, onFinish }) => {
  const [timeLeft, setTimeLeft] = useState(session.durationMinutes * 60);
  const [hasConsented, setHasConsented] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const [violations, setViolations] = useState(0);
  const [isFocusLost, setIsFocusLost] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [iframeKey, setIframeKey] = useState(0); 
  const [zoomLevel, setZoomLevel] = useState(1);
  const [panX, setPanX] = useState(0);

  const videoRef = useRef<HTMLVideoElement>(null);
  const wakeLockRef = useRef<any>(null);
  const lastViolationTime = useRef(0);

  const MAX_VIOLATIONS = 3;
  // Offset yang lebih besar untuk benar-benar membuang toolbar Google keluar viewport
  const CLIPPING_OFFSET = 120; 

  const currentStudentData = students.find(s => String(s.nis) === String(student.nis));
  const isBlocked = currentStudentData?.status === StudentStatus.BLOKIR;

  // Fungsi untuk membersihkan URL Google Drive agar menggunakan mode Preview yang lebih bersih
  const sanitizePdfUrl = (url: string) => {
    if (!url) return '';
    let sanitized = url;
    if (url.includes('drive.google.com')) {
      sanitized = url.replace(/\/view(\?.*)?$/, '/preview');
      if (!sanitized.includes('/preview')) {
        sanitized = sanitized.replace(/\/edit(\?.*)?$/, '/preview');
      }
      // Tambahkan parameter untuk meminimalisir UI
      const separator = sanitized.includes('?') ? '&' : '?';
      sanitized = `${sanitized}${separator}rm=minimal`;
    }
    return sanitized;
  };

  const requestWakeLock = async () => {
    try {
      if ('wakeLock' in navigator) {
        wakeLockRef.current = await (navigator as any).wakeLock.request('screen');
      }
    } catch (err) {}
  };

  const releaseWakeLock = useCallback(() => {
    if (wakeLockRef.current) {
      wakeLockRef.current.release();
      wakeLockRef.current = null;
    }
  }, []);

  const triggerViolation = useCallback((reason: string) => {
    if (isBlocked) return;
    const now = Date.now();
    if (now - lastViolationTime.current < 2500) return; 
    lastViolationTime.current = now;
    setIsFocusLost(true);
    setViolations(v => v + 1);
  }, [isBlocked]);

  // Handle refresh and protection
  useEffect(() => {
    const handleContextMenu = (e: MouseEvent) => e.preventDefault();
    const handleKeyDown = (e: KeyboardEvent) => {
      // Blokir Ctrl+P, Ctrl+S, Ctrl+U, F12
      if (
        (e.ctrlKey && (e.key === 'p' || e.key === 's' || e.key === 'u')) ||
        e.key === 'F12'
      ) {
        e.preventDefault();
        triggerViolation("Unauthorized Shortcut");
      }
    };

    window.addEventListener('contextmenu', handleContextMenu);
    window.addEventListener('keydown', handleKeyDown);
    return () => {
      window.removeEventListener('contextmenu', handleContextMenu);
      window.removeEventListener('keydown', handleKeyDown);
    };
  }, [triggerViolation]);

  const handleRefreshPDF = () => {
    setIframeKey(prev => prev + 1);
    setZoomLevel(1);
    setPanX(0);
  };

  const handleZoom = (delta: number) => {
    setZoomLevel(prev => Math.min(Math.max(prev + delta, 0.6), 4.0));
  };

  const handlePan = (delta: number) => {
    setPanX(prev => Math.min(Math.max(prev + delta, -800), 800));
  };

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);

    const timer = setInterval(() => {
      if (hasConsented && timeLeft > 0 && !isBlocked) setTimeLeft(prev => prev - 1);
    }, 1000);

    return () => {
      document.removeEventListener('fullscreenchange', handleFsChange);
      clearInterval(timer);
      releaseWakeLock();
    };
  }, [hasConsented, timeLeft, releaseWakeLock, isBlocked]);

  useEffect(() => {
    if (!hasConsented || isBlocked) return;
    const handleVisibilityChange = () => { if (document.hidden) triggerViolation("App Switched"); };
    const handleBlur = () => triggerViolation("Window Blur");
    window.addEventListener('visibilitychange', handleVisibilityChange);
    window.addEventListener('blur', handleBlur);
    return () => {
      window.removeEventListener('visibilitychange', handleVisibilityChange);
      window.removeEventListener('blur', handleBlur);
    };
  }, [hasConsented, triggerViolation, isBlocked]);

  const startPersistence = async () => {
    try {
      if (navigator.mediaDevices?.getUserMedia) {
        const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' } }).catch(() => null);
        if (stream && videoRef.current) {
          videoRef.current.srcObject = stream;
          videoRef.current.play().catch(() => {});
        }
      }
      const elem = document.documentElement;
      if (elem.requestFullscreen) await elem.requestFullscreen();
      await requestWakeLock();
      setHasConsented(true);
    } catch (err) {
      setHasConsented(true);
    }
  };

  useEffect(() => {
    if (violations >= MAX_VIOLATIONS) {
      onFinish();
    }
  }, [violations, onFinish]);

  return (
    <div className="flex flex-col h-screen w-screen overflow-hidden select-none bg-slate-950 font-sans relative">
      <video ref={videoRef} className="hidden" aria-hidden="true" muted playsInline />

      {/* MODAL BLOKIR */}
      {isBlocked && (
        <div className="fixed inset-0 z-[10000] bg-red-600 flex items-center justify-center p-6 backdrop-blur-xl">
          <div className="bg-white w-full max-sm p-10 rounded-[3rem] text-center shadow-2xl">
            <h2 className="text-2xl font-black text-slate-900 mb-2 uppercase tracking-tighter">Akses Diblokir</h2>
            <p className="text-slate-500 text-xs font-bold uppercase mb-10">Ujian dihentikan oleh Proktor.</p>
            <button onClick={() => onFinish()} className="w-full bg-red-600 text-white py-5 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl">KONFIRMASI & KELUAR</button>
          </div>
        </div>
      )}

      {/* OVERLAY CONSENT */}
      {!hasConsented && !isBlocked && (
        <div className="fixed inset-0 z-[1000] bg-slate-950 flex items-center justify-center p-6 backdrop-blur-md">
          <div className="bg-white w-full max-w-sm p-10 rounded-[3rem] text-center shadow-2xl">
            <h2 className="text-xl font-black text-slate-900 mb-2 uppercase tracking-tight leading-none">Siap Ujian?</h2>
            <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest mt-4 mb-10 leading-relaxed">Sistem akan mengunci layar secara otomatis dan memproteksi soal.</p>
            <button onClick={startPersistence} className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl">Masuk Mode Ujian</button>
          </div>
        </div>
      )}

      {/* HEADER */}
      <header className="h-14 md:h-20 shrink-0 z-50 border-b border-white/5 bg-black/80 backdrop-blur-2xl flex items-center px-4 md:px-10">
        <div className="flex-1 overflow-hidden">
          <h2 className="text-white font-black uppercase truncate text-[10px] md:text-sm">{student.name}</h2>
          <span className="text-indigo-400 font-bold uppercase tracking-widest text-[8px] md:text-[10px]">{student.class} | {student.nis}</span>
        </div>
        <div className="flex-1 text-center hidden sm:block">
          <h1 className="text-white font-black uppercase tracking-tighter truncate text-xs md:text-lg">{session.name}</h1>
        </div>
        <div className="flex-1 flex items-center justify-end gap-2 md:gap-4">
          <button onClick={handleRefreshPDF} className="p-2 md:p-3 bg-white/5 hover:bg-white/10 text-white rounded-xl border border-white/10 transition-all active:scale-90" title="Refresh Soal">
            <svg xmlns="http://www.w3.org/2000/svg" className={`h-4 w-4 md:h-5 md:w-5 ${iframeKey > 0 ? 'animate-spin-once' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
            </svg>
          </button>
          <div className={`font-mono font-black text-xs md:text-lg ${timeLeft < 300 ? 'text-red-500 animate-pulse' : 'text-indigo-400'}`}>
            {Math.floor(timeLeft / 60)}:{(timeLeft % 60).toString().padStart(2, '0')}
          </div>
          <button onClick={() => setShowConfirm(true)} className="bg-emerald-500 text-white px-4 md:px-8 py-2 md:py-3 rounded-xl font-black uppercase text-[9px] md:text-xs tracking-widest active:scale-90 transition-all shadow-lg shadow-emerald-500/20">Selesai</button>
        </div>
      </header>

      {/* VIEWPORT DENGAN DEEP SHIELDING */}
      <main className={`flex-1 bg-slate-900 relative transition-all duration-300 overflow-hidden ${isFocusLost || isBlocked ? 'blur-3xl pointer-events-none' : ''}`}>

        {/* Kontainer Scrollable */}
        <div className="w-full h-full relative overflow-hidden bg-slate-900">

          {/* Zoom & Pan Wrapper */}
          <div 
            className="w-full h-full transition-transform duration-200 origin-top-center will-change-transform"
            style={{ transform: `scale(${zoomLevel}) translateX(${panX}px)` }}
          >
            {/* Protective Box: Memotong area toolbar Google PDF secara fisik */}
            <div 
              className="relative w-full h-full overflow-hidden" 
              style={{ 
                marginTop: `-${CLIPPING_OFFSET}px`, 
                height: `calc(100% + ${CLIPPING_OFFSET * 2}px)` 
              }}
            >
              {hasConsented && session.pdfUrl && (
                <iframe 
                  key={iframeKey} 
                  src={sanitizePdfUrl(session.pdfUrl)} 
                  className="w-full h-full border-none" 
                  title="Soal PDF" 
                />
              )}
            </div>
          </div>
        </div>

        {/* --- INVISIBLE INTERACTION SHIELDS --- */}
        {/* 1. Top Shield: Memblokir munculnya toolbar navigasi atas iframe */}
        <div className="absolute top-0 left-0 right-0 h-24 z-[100] bg-transparent cursor-default pointer-events-auto"></div>

        {/* 2. Right Corner Shield: Memblokir tombol 'Pop-out' (Buka di jendela baru) yang sangat kritikal */}
        <div className="absolute top-0 right-0 w-32 h-32 z-[110] bg-transparent cursor-default pointer-events-auto"></div>

        {/* 3. Left Shield: Memblokir menu navigasi samping jika ada */}
        <div className="absolute top-0 left-0 w-16 bottom-0 z-[105] bg-transparent cursor-default pointer-events-auto"></div>

        {/* Watermark anti-cam (Z-90 - Di bawah shield utama tapi di atas PDF) */}
        <div className="absolute inset-0 z-[90] pointer-events-none opacity-[0.05] overflow-hidden">
           <div className="flex flex-wrap -rotate-[25deg] scale-[3] absolute -inset-[150%] w-[400%] h-[400%] items-center justify-center content-center">
             {[...Array(300)].map((_, i) => (
               <div key={i} className="text-white text-[9px] font-black p-10 uppercase tracking-[0.3em]">{student.nis} {student.name}</div>
             ))}
           </div>
        </div>

        {/* FLOATING CONTROL CENTER */}
        <div className="absolute bottom-10 left-1/2 -translate-x-1/2 z-[200] flex flex-col md:flex-row items-center gap-2 p-2.5 bg-slate-900/90 backdrop-blur-3xl border border-white/20 rounded-[2.5rem] shadow-[0_20px_50px_rgba(0,0,0,0.5)] scale-90 md:scale-100">

          {/* Pan Controls */}
          <div className="flex items-center gap-1.5">
            <button onClick={() => handlePan(80)} className="w-11 h-11 flex items-center justify-center bg-white/5 hover:bg-white/15 text-white rounded-full transition-all active:scale-90 border border-white/10">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15 19l-7-7 7-7" /></svg>
            </button>
            <div className="w-10 text-center">
              <span className="text-white/40 text-[8px] font-black uppercase tracking-tighter">Pan</span>
            </div>
            <button onClick={() => handlePan(-80)} className="w-11 h-11 flex items-center justify-center bg-white/5 hover:bg-white/15 text-white rounded-full transition-all active:scale-90 border border-white/10">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M9 5l7 7-7 7" /></svg>
            </button>
          </div>

          <div className="w-px h-8 bg-white/10 hidden md:block mx-1"></div>
          <div className="h-px w-full bg-white/10 block md:hidden my-1"></div>

          {/* Zoom Controls */}
          <div className="flex items-center gap-1.5">
