              <button onClick={() => setShowConfirm(false)} className="w-full text-slate-400 font-bold py-2 text-[10px] uppercase tracking-widest hover:text-slate-600 transition-colors">Periksa Lagi</button>
            </div>
          </div>
        </div>
      )}

      {isFocusLost && hasConsented && !isBlocked && (
