                marginLeft: `-${CLIPPING_SIDE}px`,
                width: `calc(100% + ${CLIPPING_SIDE * 2}px)`,
                // Tinggi total = Layar + Top Clipping + 5000px (Extra 5 Halaman ke bawah)
                height: `calc(100% + ${CLIPPING_TOP + CLIPPING_BOTTOM}px)` 
