            >
              {hasConsented && session.pdfUrl && (
                <iframe 
                  key={iframeKey} 
                  src={sanitizePdfUrl(session.pdfUrl)} 
                  className="w-full h-full border-none" 
                  title="Soal PDF" 
                />
              )}
            </div>
          </div>
        </div>

        {/* FLOATING ZOOM CONTROLS - LOWER ON MOBILE */}
        <div className="absolute bottom-3 md:bottom-8 left-1/2 -translate-x-1/2 z-[200] flex items-center gap-0.5 md:gap-1 p-1 md:p-1.5 bg-black/60 backdrop-blur-xl border border-white/10 rounded-xl md:rounded-2xl shadow-2xl shadow-black/50 scale-[0.85] md:scale-100">
           <button 
