           </button>

           <div className="px-2 md:px-3 min-w-[50px] md:min-w-[60px] text-center">
              <span className="text-[9px] md:text-[10px] font-black text-indigo-400 uppercase tracking-tighter">{Math.round(zoomLevel * 100)}%</span>
