            <svg xmlns="http://www.w3.org/2000/svg" className={`h-3 w-3 md:h-5 md:w-5 landscape:h-2.5 md:landscape:h-5 landscape:w-2.5 md:landscape:w-5 ${iframeKey > 0 ? 'animate-spin-once' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
