        <div className="w-full h-full overflow-auto scrollbar-hide">

          {/* Zoom Wrapper */}
          <div 
            className="w-full h-full relative transition-transform duration-300 ease-out origin-top"
            style={{ transform: `scale(${zoomLevel})` }}
          >
            {/* 
                PROTECTIVE CROPPING FRAME (ULTRA EXTENDED):
                Iframe dibuat sangat tinggi ke bawah (+5000px) agar kontrol navigasi/zoom 
                bawaan Google PDF tidak pernah muncul di viewport siswa.
            */}
            <div 
              className="relative w-full h-full overflow-hidden" 
              style={{ 
                marginTop: `-${CLIPPING_TOP}px`, 
                marginLeft: `-${CLIPPING_SIDE}px`,
                width: `calc(100% + ${CLIPPING_SIDE * 2}px)`,
