          <button onClick={() => setShowConfirm(true)} className="bg-emerald-500 text-white px-4 md:px-8 py-2 md:py-3 rounded-xl font-black uppercase text-[9px] md:text-xs tracking-widest shadow-lg active:scale-90 transition-all">Selesai</button>
        </div>
      </header>

      {/* VIEWPORT */}
      <main className={`flex-1 bg-slate-900 relative transition-all duration-300 overflow-hidden ${isFocusLost || isBlocked ? 'blur-3xl pointer-events-none' : ''}`}>
        <div className="w-full h-full overflow-auto scrollbar-hide">
          <div 
