        </div>
        <div className="flex-1 text-center hidden sm:landscape:max-h-[500px]:hidden sm:block">
          <h1 className="text-white font-black uppercase tracking-tighter truncate text-xs md:text-lg">{session.name}</h1>
        </div>
        <div className="flex-1 flex items-center justify-end gap-3 md:gap-4 landscape:max-h-[500px]:gap-2">
          <button onClick={handleRefreshPDF} className="p-2 md:p-3 landscape:max-h-[500px]:p-1 bg-white/5 hover:bg-white/10 text-white rounded-xl border border-white/10 transition-all active:scale-90" title="Refresh Soal">
            <svg xmlns="http://www.w3.org/2000/svg" className={`h-4 w-4 md:h-5 md:w-5 landscape:max-h-[500px]:h-3 landscape:max-h-[500px]:w-3 ${iframeKey > 0 ? 'animate-spin-once' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
            </svg>
          </button>
          <div className={`font-mono font-black text-sm md:text-lg landscape:max-h-[500px]:text-xs ${timeLeft < 300 ? 'text-red-500 animate-pulse' : 'text-indigo-400'}`}>
