          </div>
          <button onClick={() => setShowConfirm(true)} className="bg-emerald-500 text-white px-4 md:px-8 landscape:max-h-[500px]:px-3 py-2 md:py-3 landscape:max-h-[500px]:py-1 rounded-xl font-black uppercase text-[9px] md:text-xs landscape:max-h-[500px]:text-[7px] tracking-widest shadow-lg active:scale-90 transition-all">Selesai</button>
        </div>
