              )}
            </div>
          </div>
        </div>

        {/* FLOATING ZOOM CONTROLS - PERBAIKAN POSISI LANDSCAPE HP */}
        <div className="absolute 
          bottom-6 right-4 flex flex-col items-center gap-2 p-2 bg-black/40 backdrop-blur-xl border border-white/10 rounded-[1.5rem] shadow-2xl opacity-40 hover:opacity-100 transition-all duration-300 z-[200]
