import React, { useState, useEffect, Suspense, lazy } from 'react';
import { ViewState, Student, ExamSession, StudentStatus, Room } from './types';
import { fetchFromCloud, callCloudAction } from './services/databaseService';

const StudentLogin = lazy(() => import('./views/StudentLogin'));
const AdminLogin = lazy(() => import('./views/AdminLogin'));
const AdminDashboard = lazy(() => import('./views/AdminDashboard'));
const ProctorDashboard = lazy(() => import('./views/ProctorDashboard'));
const ExamRoom = lazy(() => import('./views/ExamRoom'));

const GAS_URL = "https://script.google.com/macros/s/AKfycbxJbQdOa7nhOpKlBwcdjpOCpEdcN4YFjUaCTS376dUS1ttJZe6Ii9AS3z5ECfTKuVf7ig/exec"; 

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('STUDENT_LOGIN');
  const [currentUser, setCurrentUser] = useState<Student | null>(null);
  const [currentSession, setCurrentSession] = useState<ExamSession | null>(null);
  const [activeRoom, setActiveRoom] = useState<Room | null>(null);

  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false); // State untuk aksi manual
  const [hasError, setHasError] = useState(false);
  const [errorDetail, setErrorDetail] = useState('');

  const [students, setStudents] = useState<Student[]>([]);
  const [sessions, setSessions] = useState<ExamSession[]>([]);
  const [rooms, setRooms] = useState<Room[]>([]);

  const loadAllData = async () => {
    if (!GAS_URL) return;

    setIsSyncing(true);
    const cloudData = await fetchFromCloud(GAS_URL);

    if (cloudData) {
      setStudents(cloudData.students || []);
      setSessions(cloudData.sessions || []);
      setRooms(cloudData.rooms || []);
      localStorage.setItem('examsy_backup', JSON.stringify(cloudData));
      setHasError(false);
      setErrorDetail('');
    } else {
      const backup = localStorage.getItem('examsy_backup');
      if (backup) {
        const parsed = JSON.parse(backup);
        setStudents(parsed.students || []);
        setSessions(parsed.sessions || []);
        setRooms(parsed.rooms || []);
      }
      setHasError(true);
      setErrorDetail('Gagal terhubung ke Cloud. Pastikan internet aktif.');
    }
    setIsLoading(false);
    setIsSyncing(false);
  };

  useEffect(() => {
    loadAllData();
    const intervalTime = (view === 'EXAM_ROOM' || view === 'PROCTOR_DASHBOARD' || view === 'ADMIN_DASHBOARD') ? 15000 : 60000;
    const interval = setInterval(() => {
      loadAllData();
    }, intervalTime);
    return () => clearInterval(interval);
  }, [view]);

  const handleAction = async (action: string, payload: any) => {
    setIsProcessing(true);
    setIsSyncing(true);

    // Optimistic Update
    if (action === 'UPDATE_STUDENT') {
      setStudents(prev => prev.map(s => 
        String(s.nis) === String(payload.nis) ? { ...s, ...payload } : s
      ));
    }

    const success = await callCloudAction(GAS_URL, action, payload);

    if (success) {
      await loadAllData();
    } else {
      await loadAllData();
    }

    setIsSyncing(false);
    setIsProcessing(false);
    return success;
  };

  const handleStudentLogin = async (student: Student, session: ExamSession) => {
    setIsProcessing(true);
    const success = await handleAction('UPDATE_STUDENT', { ...student, status: StudentStatus.SEDANG_UJIAN });
    if (success) {
      setCurrentUser(student);
      setCurrentSession(session);
      setView('EXAM_ROOM');
    }
    setIsProcessing(false);
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-900 flex flex-col items-center justify-center p-10 text-center">
        <div className="w-12 h-12 border-4 border-indigo-500/20 border-t-indigo-500 rounded-full animate-spin mb-6"></div>
        <h2 className="text-white font-black uppercase tracking-widest text-[10px]">Menghubungkan ke Database...</h2>
        {hasError && <p className="text-red-400 text-[10px] mt-4 font-bold">{errorDetail}</p>}
        {hasError && (
          <button 
            onClick={() => { setIsLoading(true); loadAllData(); }} 
            className="mt-6 bg-white/10 text-white px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest"
          >
            Coba Lagi
          </button>
        )}
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 overflow-x-hidden relative">
      {/* Global Sync Indicator (Top Progress Bar) */}
      {isSyncing && (
        <div className="fixed top-0 left-0 right-0 h-1 z-[10001] bg-indigo-100 overflow-hidden">
          <div className="h-full bg-indigo-600 animate-[loading_2s_infinite_linear] origin-left w-1/3"></div>
        </div>
      )}

      {hasError && (
        <div className="fixed top-0 left-0 right-0 z-[9999] bg-red-600 text-white py-2 px-4 text-center text-[10px] font-black uppercase tracking-widest animate-in slide-in-from-top duration-500">
          ⚠️ Masalah Koneksi. Menggunakan Data Terakhir.
          <button onClick={() => loadAllData()} className="ml-4 underline">Segarkan</button>
        </div>
      )}

      <Suspense fallback={<div className="min-h-screen flex items-center justify-center bg-slate-50"><div className="w-8 h-8 border-3 border-indigo-500/10 border-t-indigo-500 rounded-full animate-spin"></div></div>}>
        {view === 'STUDENT_LOGIN' && <StudentLogin sessions={sessions} students={students} onLogin={handleStudentLogin} onAdminClick={() => setView('ADMIN_LOGIN')} isProcessing={isProcessing} />}
        {view === 'ADMIN_LOGIN' && <AdminLogin rooms={rooms} onLogin={(role, r) => { if(role==='ADMIN') setView('ADMIN_DASHBOARD'); else { setActiveRoom(r!); setView('PROCTOR_DASHBOARD'); } }} onBack={() => setView('STUDENT_LOGIN')} />}
        {view === 'ADMIN_DASHBOARD' && <AdminDashboard sessions={sessions} students={students} rooms={rooms} isSyncing={isSyncing} isProcessing={isProcessing} onLogout={() => setView('STUDENT_LOGIN')} onAction={handleAction} />}
        {view === 'PROCTOR_DASHBOARD' && activeRoom && <ProctorDashboard room={activeRoom} students={students} isSyncing={isSyncing} isProcessing={isProcessing} onLogout={() => setView('STUDENT_LOGIN')} onAction={handleAction} gasUrl={GAS_URL} />}
        {view === 'EXAM_ROOM' && currentUser && currentSession && <ExamRoom student={currentUser} students={students} session={currentSession} onFinish={() => { setCurrentUser(null); setCurrentSession(null); setView('STUDENT_LOGIN'); }} />}
      </Suspense>

      <style>{`
        @keyframes loading {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(300%); }
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { ExamSession, Student, StudentStatus } from '../types';

interface StudentLoginProps {
  sessions: ExamSession[];
  students: Student[];
  onLogin: (student: Student, session: ExamSession) => void;
  onAdminClick: () => void;
  isProcessing?: boolean;
}

const StudentLogin: React.FC<StudentLoginProps> = ({ sessions, students, onLogin, onAdminClick, isProcessing = false }) => {
  const LOGO_URL = "https://www.alirsyad.or.id/wp-content/uploads/download/alirsyad-alislamiyyah-bw.png"; 

  const [formData, setFormData] = useState({
    nis: '',
    password: '',
    studentClass: '',
    pin: ''
  });
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (isProcessing) return;
    setError('');

    const inputNis = String(formData.nis).trim();
    const inputPass = String(formData.password).trim();
    const inputClass = String(formData.studentClass).trim();
    const inputPin = String(formData.pin).trim().toUpperCase();

    // 1. Cari Siswa berdasarkan NIS & Password
    const student = students.find(s => 
      String(s.nis).trim() === inputNis && 
      String(s.password || '').trim() === inputPass
    );

    if (!student) {
      setError('NIS atau Password Anda tidak terdaftar.');
      return;
    }

    // 2. Cek Status Akun
    if (student.status === StudentStatus.BLOKIR) {
      setError('Akses ditolak. Akun Anda dalam status BLOKIR.');
      return;
    }

    if (student.status === StudentStatus.SELESAI) {
      setError('Anda telah menyelesaikan sesi ujian ini.');
      return;
    }

    // 3. Sinkronisasi Data Kelas Siswa
    if (String(student.class).trim() !== inputClass) {
      setError(`Sinkronisasi Gagal: Anda terdaftar di Kelas ${student.class}, bukan Kelas ${inputClass}.`);
      return;
    }

    // 4. Cari Sesi Aktif berdasarkan PIN
    const session = sessions.find(s => 
      String(s.pin || '').trim().toUpperCase() === inputPin && 
      s.isActive
    );

    if (!session) {
      setError('PIN Sesi tidak aktif atau tidak ditemukan.');
      return;
    }

    // 5. Sinkronisasi Data Kelas Sesi
    if (String(session.class).trim() !== inputClass) {
      setError(`Sesi ${session.name} hanya untuk Kelas ${session.class}. Silakan pilih kelas yang sesuai.`);
      return;
    }

    // Jika semua valid, lanjut ke Ruang Ujian
    onLogin(student, session);
  };

  return (
    <div className="relative flex flex-col items-center justify-center min-h-screen p-6 bg-slate-50">
      <button 
        onClick={onAdminClick}
        disabled={isProcessing}
        className="absolute top-6 right-6 p-3 text-slate-400 hover:text-indigo-600 hover:bg-white hover:shadow-md rounded-full transition-all duration-300 group disabled:opacity-50"
        title="Portal Staff"
      >
        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 group-hover:rotate-90 transition-transform duration-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
        </svg>
      </button>

      <div className="w-full max-w-md bg-white p-10 rounded-[2.5rem] shadow-2xl shadow-slate-200/50 border border-slate-100">
        <div className="text-center mb-10 flex flex-col items-center">
          <div className="mb-6 w-24 h-24 bg-white rounded-3xl flex items-center justify-center border border-slate-100 shadow-sm overflow-hidden p-2">
            <img 
              src={LOGO_URL} 
              alt="Logo" 
              className="w-full h-full object-contain"
              onError={(e) => { (e.target as HTMLImageElement).src = "https://via.placeholder.com/150?text=AL-IRSYAD"; }}
            />
          </div>

          <h1 className="text-2xl md:text-3xl font-black text-indigo-600 mb-1 tracking-tighter uppercase drop-shadow-sm">
            EXAM SEMI-ONLINE
          </h1>
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em]">SMP Al Irsyad Surakarta</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="space-y-1.5">
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nomor Induk Siswa</label>
            <input
              type="text"
              required
              disabled={isProcessing}
              value={formData.nis}
              onChange={e => setFormData({...formData, nis: e.target.value})}
              className="w-full px-6 py-4 rounded-2xl border border-slate-100 bg-slate-50 focus:bg-white focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-bold disabled:opacity-70"
              placeholder="Contoh: 1234"
            />
          </div>

          <div className="space-y-1.5">
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Password</label>
            <div className="relative">
              <input
                type={showPassword ? "text" : "password"}
                required
                disabled={isProcessing}
                value={formData.password}
                onChange={e => setFormData({...formData, password: e.target.value})}
                className="w-full px-6 py-4 rounded-2xl border border-slate-100 bg-slate-50 focus:bg-white focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-bold pr-14 disabled:opacity-70"
                placeholder="••••••••"
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                className="absolute right-4 top-1/2 -translate-y-1/2 p-2 text-slate-400 hover:text-indigo-600 transition-colors"
              >
                {showPassword ? (
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l18 18" />
                  </svg>
                ) : (
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268-2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
                  </svg>
                )}
              </button>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1.5">
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Pilih Kelas</label>
              <select
                required
                disabled={isProcessing}
                value={formData.studentClass}
                onChange={e => setFormData({...formData, studentClass: e.target.value})}
                className="w-full px-5 py-4 rounded-2xl border border-slate-100 bg-slate-50 focus:bg-white focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-bold appearance-none disabled:opacity-70"
              >
                <option value="">Kelas</option>
                <option value="7">Kls 7</option>
                <option value="8">Kls 8</option>
                <option value="9">Kls 9</option>
              </select>
            </div>
            <div className="space-y-1.5">
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">PIN Sesi</label>
              <input
                type="text"
                required
                disabled={isProcessing}
                value={formData.pin}
                onChange={e => setFormData({...formData, pin: e.target.value})}
                className="w-full px-5 py-4 rounded-2xl border border-slate-100 bg-slate-50 focus:bg-white focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all text-center tracking-widest font-mono font-black uppercase disabled:opacity-70"
                placeholder="PIN"
              />
            </div>
          </div>

          {error && (
            <div className="flex items-center gap-3 text-red-600 text-[11px] font-bold bg-red-50 p-4 rounded-2xl border border-red-100 animate-in slide-in-from-top-2">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 shrink-0" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
              </svg>
              {error}
            </div>
          )}

          <button
            type="submit"
            disabled={isProcessing}
            className="w-full bg-indigo-600 hover:bg-indigo-700 disabled:bg-indigo-400 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 transition-all active:scale-[0.98] mt-4 uppercase text-xs tracking-widest flex items-center justify-center gap-3"
