                          alt="" 
                        />
                        <div>
                          <p className="font-black text-slate-800 text-sm">{student?.name || 'User Dihapus'}</p>
                          <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">@{student?.username || 'unknown'}</p>
