                </div>
              )}
            </div>
          </div>
        </header>

        {/* Scrollable Content Area */}
        <div className="flex-1 overflow-y-auto p-4 md:p-12 scrollbar-hide">
          {children}
        </div>
      </main>

      {/* Mobile Bottom Navigation */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 flex justify-around items-center h-16 px-2 z-50 shadow-[0_-10px_40px_rgba(0,0,0,0.05)] rounded-t-[1.5rem] md:rounded-t-[2.5rem]">
        {/* Main navigation items (Home, Materials, Tasks, and Grades for Students) */}
        {sidebarItems.slice(0, 4).map((item) => (
          <button
            key={item.id}
            onClick={() => setActiveView(item.id)}
            className={`flex flex-col items-center gap-1 p-2 rounded-xl transition-all ${
              activeView === item.id ? 'bg-slate-900 text-white shadow-lg scale-105' : 'text-slate-400'
            }`}
          >
            <item.icon size={20} />
          </button>
        ))}
        {/* Settings button is always at the end on mobile nav */}
        <button
          onClick={() => setActiveView('settings')}
          className={`flex flex-col items-center gap-1 p-2 rounded-xl transition-all ${
            activeView === 'settings' ? 'bg-slate-900 text-white shadow-lg scale-105' : 'text-slate-400'
          }`}
        >
          <UserIcon size={20} />
        </button>
      </nav>
    </div>
  );
};

export default Layout;

import React, { useState, useEffect } from 'react';
import { BarChart3, BookOpen, ClipboardList, Users, School, Settings, UserPlus, CheckCircle, AlertTriangle } from 'lucide-react';
import Layout from '../components/Layout.tsx';
import { User, SiteSettings, ClassRoom } from '../types.ts';
import { db } from '../App.tsx';
import { firestore } from '../firebase';
import { collection, query, where, onSnapshot } from "firebase/firestore";

import OverviewTab from './admin/OverviewTab.tsx';
import ConfirmRegistrationsTab from './admin/ConfirmRegistrationsTab.tsx';
import ManageMaterialsTab from './admin/ManageMaterialsTab.tsx';
import ManageTasksTab from './admin/ManageTasksTab.tsx';
import GradesTab from './admin/GradesTab.tsx';
import ManageStudentsTab from './admin/ManageStudentsTab.tsx';
import ManageClassesTab from './admin/ManageClassesTab.tsx';
import SettingsTab from './admin/SettingsTab.tsx';

interface AdminDashboardProps {
  user: User;
  onLogout: () => void;
  settings: SiteSettings;
  setSettings: React.Dispatch<React.SetStateAction<SiteSettings>>;
  onUpdateUser?: (u: User) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ user, onLogout, settings, setSettings, onUpdateUser }) => {
  const [activeView, setActiveView] = useState('overview');
  const [notifications, setNotifications] = useState<any[]>([]);
  const [classes, setClasses] = useState<ClassRoom[]>([]);
  const [confirmModal, setConfirmModal] = useState<{
    isOpen: boolean;
    title: string;
    message: string;
    onConfirm: () => void;
    type: 'danger' | 'warning';
  }>({
    isOpen: false,
    title: '',
    message: '',
    onConfirm: () => {},
    type: 'danger'
  });

  useEffect(() => {
    // 1. Real-time Notifications Listener
    const qNotifs = query(
      collection(firestore, 'elearning_notifications'), 
      where('userId', '==', user.id)
    );

    const unsubscribeNotifs = onSnapshot(qNotifs, (snapshot) => {
      const notifList = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      setNotifications(notifList);
    });

    // 2. Fetch Classes
    const fetchClasses = async () => {
      const c = await db.get('elearning_classes');
      setClasses(Array.isArray(c) ? c : []);
    };
    fetchClasses();

    return () => {
      unsubscribeNotifs();
    };
  }, [user.id]);

  const handleMarkAsRead = async (id: string) => {
    const notif = notifications.find(n => n.id === id);
    if (notif) {
      await db.update('elearning_notifications', id, { ...notif, read: true });
      // Notifications will be updated automatically via onSnapshot listener
    }
  };

  const handleMarkAllRead = async () => {
    const updated = notifications.filter(n => !n.read).map(n => ({ ...n, read: true }));
    if (updated.length > 0) {
      await db.saveAll('elearning_notifications', updated);
      // Notifications will be updated automatically via onSnapshot listener
    }
  };

  const sidebarItems = [
    { id: 'overview', label: 'Ringkasan', icon: BarChart3 },
    { id: 'confirmations', label: 'Konfirmasi Siswa', icon: UserPlus },
    { id: 'materials', label: 'Kelola Materi', icon: BookOpen },
    { id: 'tasks', label: 'Kelola Tugas', icon: ClipboardList },
    { id: 'grades', label: 'Nilai Tugas', icon: CheckCircle },
    { id: 'students', label: 'Kelola Siswa', icon: Users },
    { id: 'classes', label: 'Kelola Kelas', icon: School },
    { id: 'settings', label: 'Pengaturan', icon: Settings },
  ];

  const triggerConfirm = (title: string, message: string, onConfirm: () => void, type: 'danger' | 'warning' = 'danger') => {
    setConfirmModal({ isOpen: true, title, message, onConfirm, type });
  };

  const closeConfirm = () => setConfirmModal(prev => ({ ...prev, isOpen: false }));

  const renderContent = () => {
    switch (activeView) {
      case 'overview': return <OverviewTab setActiveView={setActiveView} />;
      case 'confirmations': return <ConfirmRegistrationsTab triggerConfirm={triggerConfirm} />;
      case 'materials': return <ManageMaterialsTab triggerConfirm={triggerConfirm} classes={classes} />;
      case 'tasks': return <ManageTasksTab triggerConfirm={triggerConfirm} classes={classes} />;
      case 'grades': return <GradesTab triggerConfirm={triggerConfirm} classes={classes} />;
      case 'students': return <ManageStudentsTab triggerConfirm={triggerConfirm} classes={classes} />;
      case 'classes': return <ManageClassesTab triggerConfirm={triggerConfirm} classes={classes} setClasses={setClasses} />;
      case 'settings': return <SettingsTab settings={settings} setSettings={setSettings} user={user} onUpdateUser={onUpdateUser!} />;
      default: return <OverviewTab setActiveView={setActiveView} />;
    }
  };

  return (
    <Layout 
      user={user} 
      onLogout={onLogout} 
      sidebarItems={sidebarItems} 
      activeView={activeView} 
      setActiveView={setActiveView}
      logoUrl={settings.logoUrl}
      siteName={settings.siteName}
      notifications={notifications}
      onMarkAsRead={handleMarkAsRead}
      onMarkAllAsRead={handleMarkAllRead}
    >
      {renderContent()}

      {confirmModal.isOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-6 text-black">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] p-10 shadow-2xl animate-in zoom-in-95 duration-200 text-center">
            <div className={`w-20 h-20 mx-auto rounded-3xl flex items-center justify-center mb-6 ${confirmModal.type === 'danger' ? 'bg-red-50 text-red-500' : 'bg-orange-50 text-orange-500'}`}>
              <AlertTriangle size={40} className={confirmModal.type === 'danger' ? 'text-red-500' : 'text-orange-500'} />
            </div>
            <h3 className="text-2xl font-black text-slate-800 mb-2">{confirmModal.title}</h3>
            <p className="text-slate-500 font-medium text-sm leading-relaxed mb-10">{confirmModal.message}</p>
            <div className="flex gap-4">
              <button onClick={closeConfirm} className="flex-1 py-4 bg-slate-50 text-slate-500 rounded-2xl font-black text-sm hover:bg-slate-100 transition-all">Batal</button>
              <button onClick={() => { confirmModal.onConfirm(); closeConfirm(); }} className={`flex-1 py-4 text-white rounded-2xl font-black text-sm shadow-xl transition-all ${confirmModal.type === 'danger' ? 'bg-red-500 hover:bg-red-600' : 'bg-orange-500 hover:bg-orange-600'}`}>Ya, Lanjutkan</button>
            </div>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default AdminDashboard;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { 
  LogOut, User as UserIcon, Bell, X, Check, 
  Info, BookOpen, ClipboardList, CheckCircle, 
  UserPlus, ChevronDown, Settings, UserCircle,
  Users, BarChart3
} from 'lucide-react';

interface Notification {
  id: string;
  title: string;
  message: string;
  read: boolean;
  type: 'material' | 'task' | 'grade' | 'registration';
  createdAt: string;
}

interface LayoutProps {
  children: React.ReactNode;
  user: any;
  onLogout: () => void;
  sidebarItems: { icon: any; label: string; id: string }[];
  activeView: string;
  setActiveView: (id: string) => void;
  logoUrl: string;
  siteName: string;
  notifications?: Notification[];
  onMarkAsRead?: (id: string) => void;
  onMarkAllAsRead?: () => void;
}

const Layout: React.FC<LayoutProps> = ({ 
  children, 
  user, 
  onLogout, 
  sidebarItems, 
  activeView, 
  setActiveView,
  logoUrl,
  siteName,
  notifications = [],
  onMarkAsRead,
  onMarkAllAsRead
}) => {
  const [showNotifications, setShowNotifications] = useState(false);
  const [showProfileMenu, setShowProfileMenu] = useState(false);

  const sortedNotifications = useMemo(() => {
    return [...notifications].sort((a, b) => {
      const timeA = a.createdAt ? new Date(a.createdAt).getTime() : 0;
      const timeB = b.createdAt ? new Date(b.createdAt).getTime() : 0;

      const valA = isNaN(timeA) ? 0 : timeA;
      const valB = isNaN(timeB) ? 0 : timeB;

      return valB - valA;
    });
  }, [notifications]);

  const unreadCount = useMemo(() => {
    return notifications.filter(n => !n.read).length;
  }, [notifications]);

  const notificationRef = useRef<HTMLDivElement>(null);
  const profileRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
      if (profileRef.current && !profileRef.current.contains(event.target as Node)) {
        setShowProfileMenu(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const getIcon = (type: string) => {
    switch(type) {
      case 'material': return <BookOpen size={16} className="text-emerald-500" />;
      case 'task': return <ClipboardList size={16} className="text-purple-500" />;
      case 'grade': return <CheckCircle size={16} className="text-blue-500" />;
      case 'registration': return <UserPlus size={16} className="text-orange-500" />;
      default: return <Info size={16} className="text-slate-400" />;
    }
  };

  const formatDateLabel = (isoString: string) => {
    try {
      const date = new Date(isoString);
      if (isNaN(date.getTime())) return isoString.split(',')[0];
      return date.toLocaleDateString('id-ID', { day: '2-digit', month: 'short' });
    } catch (e) {
      return isoString.split(',')[0];
    }
  };

  const NotificationBadge = ({ count }: { count: number }) => (
    count > 0 ? (
      <span className="absolute -top-1 -right-1 w-4 h-4 md:w-5 md:h-5 bg-rose-500 text-white text-[8px] md:text-[9px] font-black flex items-center justify-center rounded-full border-2 border-white shadow-lg animate-in zoom-in-50 duration-300">
        {count > 9 ? '9+' : count}
      </span>
    ) : null
  );

  // Filter items specifically for mobile bottom navigation to keep it clean but functional
  const mobileNavItems = useMemo(() => {
    if (user.role === 'ADMIN') {
      // For Admin: Overview, Confirmations, Materials, Tasks, Students
      return sidebarItems.filter(item => 
        ['overview', 'confirmations', 'materials', 'tasks', 'students'].includes(item.id)
      );
    } else {
      // For Student: Home, Materials, Tasks, Grades
      return sidebarItems.filter(item => 
        ['home', 'materials', 'tasks', 'grades'].includes(item.id)
      );
    }
  }, [user.role, sidebarItems]);

  return (
    <div className="flex min-h-screen bg-slate-50">
      {/* Sidebar Desktop */}
      <aside className="w-72 bg-white border-r border-slate-200 hidden md:flex flex-col sticky top-0 h-screen">
        <div className="p-8 flex flex-col gap-4">
          <img src={logoUrl} alt="Logo" className="h-14 w-auto object-contain self-start" />
          <span className="font-black text-slate-800 text-[10px] leading-tight opacity-40 uppercase tracking-[0.3em]">{siteName}</span>
        </div>

        <nav className="flex-1 px-4 py-4 space-y-2">
          {sidebarItems.map((item) => (
            <button
              key={item.id}
              onClick={() => setActiveView(item.id)}
              className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${
                activeView === item.id 
                  ? 'bg-slate-900 text-white shadow-2xl shadow-slate-200 translate-x-1' 
                  : 'text-slate-400 hover:bg-slate-50 hover:text-slate-600'
              }`}
            >
              <item.icon size={20} />
              {item.label}
            </button>
          ))}
        </nav>

        <div className="p-6 border-t border-slate-50">
          <div className="p-5 bg-emerald-50 rounded-[2rem] border border-emerald-100/50">
             <p className="text-[9px] font-black text-emerald-600 uppercase tracking-widest mb-1.5 flex items-center gap-2">
               <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></div>
               Status Sistem
             </p>
             <span className="text-[11px] font-bold text-slate-700">Cloud Terhubung</span>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-screen overflow-hidden">
        {/* Navbar */}
        <header className="h-16 md:h-20 bg-white/80 backdrop-blur-md border-b border-slate-200 px-4 md:px-10 flex items-center justify-between sticky top-0 z-40">
          <div className="flex items-center gap-4">
            <h2 className="text-lg md:text-xl font-black text-slate-900 tracking-tighter truncate max-w-[150px] md:max-w-none">
              {sidebarItems.find(i => i.id === activeView)?.label || 'Dashboard'}
            </h2>
          </div>

          <div className="flex items-center gap-2 md:gap-4">
            <div className="relative" ref={notificationRef}>
              <button 
                onClick={() => setShowNotifications(!showNotifications)}
                className={`p-2.5 md:p-3.5 rounded-xl md:rounded-2xl transition-all relative ${showNotifications ? 'bg-slate-900 text-white shadow-xl' : 'bg-slate-50 text-slate-400 hover:text-slate-900'}`}
              >
                <Bell size={18} className="md:w-5 md:h-5" />
                <NotificationBadge count={unreadCount} />
              </button>

              {showNotifications && (
                <div className="absolute right-0 mt-4 w-[280px] md:w-[28rem] bg-white rounded-3xl md:rounded-[3rem] shadow-2xl border border-slate-100 overflow-hidden z-50 animate-in fade-in slide-in-from-top-4 duration-300">
                  <div className="p-5 md:p-8 border-b border-slate-50 flex items-center justify-between bg-white">
                    <div>
                      <h4 className="font-black text-slate-900 text-base md:text-lg tracking-tight">Notifikasi</h4>
                      <p className="text-[8px] md:text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Kamu punya {unreadCount} pesan baru</p>
                    </div>
                    {unreadCount > 0 && (
                      <button 
                        onClick={() => {
                          onMarkAllAsRead?.();
                          setShowNotifications(false);
                        }}
                        className="text-[8px] md:text-[10px] font-black text-emerald-600 uppercase hover:bg-emerald-50 px-3 py-1.5 rounded-lg transition-all active:scale-95"
                      >
                        Tandai Semua
                      </button>
                    )}
                  </div>
                  <div className="max-h-[350px] md:max-h-[450px] overflow-y-auto scrollbar-hide bg-white">
                    {sortedNotifications.length === 0 ? (
                      <div className="py-12 md:py-20 text-center">
                        <div className="w-16 h-16 bg-slate-50 text-slate-200 rounded-2xl flex items-center justify-center mx-auto mb-4">
                           <Bell size={30} />
                        </div>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Belum ada aktivitas baru</p>
                      </div>
                    ) : (
                      sortedNotifications.map((notif) => (
                        <div 
                          key={notif.id} 
                          onClick={() => {
                            onMarkAsRead?.(notif.id);
                            if (!notif.read) setShowNotifications(false);
                          }}
                          className={`p-4 md:p-6 flex gap-4 md:gap-5 cursor-pointer transition-all border-b border-slate-50 last:border-0 ${!notif.read ? 'bg-emerald-50/30 hover:bg-emerald-50/50' : 'hover:bg-slate-50 opacity-60'}`}
                        >
                          <div className={`w-10 h-10 md:w-12 md:h-12 rounded-xl md:rounded-2xl flex items-center justify-center shrink-0 shadow-sm ${!notif.read ? 'bg-white' : 'bg-slate-100 grayscale'}`}>
                            {getIcon(notif.type)}
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex items-start justify-between gap-2 mb-0.5 md:mb-1">
                              <p className={`text-xs md:text-sm truncate ${!notif.read ? 'font-black text-slate-900' : 'font-bold text-slate-500'}`}>{notif.title}</p>
                              <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest shrink-0">{formatDateLabel(notif.createdAt)}</p>
                            </div>
                            <p className="text-[10px] md:text-xs text-slate-500 font-medium line-clamp-2 leading-relaxed">{notif.message}</p>
                          </div>
                          {!notif.read && (
                            <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full mt-2 shrink-0 shadow-[0_0_8px_rgba(16,185,129,0.8)]"></div>
                          )}
                        </div>
                      ))
                    )}
                  </div>
                </div>
              )}
            </div>

            <div className="h-8 w-[1px] bg-slate-100 mx-1 md:mx-2"></div>

            <div className="relative" ref={profileRef}>
              <button 
                onClick={() => setShowProfileMenu(!showProfileMenu)}
                className={`flex items-center gap-2 p-1 md:p-1.5 md:pr-5 rounded-full transition-all ${
                  showProfileMenu 
                    ? 'bg-slate-900 text-white shadow-2xl' 
                    : 'bg-slate-50 border border-slate-100 text-slate-800'
                }`}
              >
                <img 
                  src={user.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user.username}`} 
                  alt="Profile" 
                  className={`w-8 h-8 md:w-9 md:h-9 rounded-full border-2 ${showProfileMenu ? 'border-white/20' : 'border-white'} bg-white object-cover`}
                />
                <div className="text-left hidden sm:block">
                  <p className="text-xs font-black leading-none">{user.name.split(' ')[0]}</p>
                </div>
                <ChevronDown size={12} className={`transition-transform duration-300 hidden md:block ${showProfileMenu ? 'rotate-180' : ''}`} />
              </button>

              {showProfileMenu && (
                <div className="absolute right-0 mt-4 w-64 md:w-72 bg-white rounded-3xl md:rounded-[2.5rem] shadow-2xl border border-slate-100 overflow-hidden z-50 animate-in fade-in slide-in-from-top-4 duration-300">
                  <div className="p-6 md:p-8 bg-slate-50 border-b border-slate-100 flex flex-col items-center text-center">
                    <img 
                      src={user.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user.username}`} 
                      className="w-16 h-16 md:w-20 md:h-20 rounded-full border-4 border-white shadow-xl mb-4"
                      alt=""
                    />
                    <h5 className="text-sm md:text-base font-black text-slate-900">{user.name}</h5>
                    <p className="text-[8px] md:text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em] mt-1">Siswa Informatika</p>
                  </div>

                  <div className="p-2 md:p-3 space-y-1">
                    <button 
                      onClick={() => { setActiveView('settings'); setShowProfileMenu(false); }}
                      className="w-full flex items-center gap-3 md:gap-4 px-4 py-3 rounded-xl md:rounded-2xl text-[10px] md:text-xs font-black text-slate-600 hover:bg-slate-50 transition-colors uppercase tracking-widest"
                    >
                      <Settings size={18} className="text-slate-400" /> Profil Akun
                    </button>
                    <button 
                      onClick={onLogout}
                      className="w-full flex items-center gap-3 md:gap-4 px-4 py-3 rounded-xl md:rounded-2xl text-[10px] md:text-xs font-black text-rose-500 hover:bg-rose-50 transition-colors uppercase tracking-widest"
                    >
                      <LogOut size={18} /> Logout
                    </button>
                  </div>
                </div>
              )}
            </div>
          </div>
        </header>

        {/* Scrollable Content Area */}
        <div className="flex-1 overflow-y-auto p-4 md:p-12 scrollbar-hide">
          {children}
        </div>
      </main>

      {/* Mobile Bottom Navigation - Optimized with dynamic items based on role */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 flex justify-around items-center h-16 px-2 z-50 shadow-[0_-10px_40px_rgba(0,0,0,0.05)] rounded-t-[1.5rem]">
        {mobileNavItems.map((item) => (
          <button
            key={item.id}
            onClick={() => setActiveView(item.id)}
            className={`flex flex-col items-center gap-1 p-2.5 rounded-xl transition-all ${
              activeView === item.id ? 'bg-slate-900 text-white shadow-lg scale-110 -translate-y-1' : 'text-slate-400'
            }`}
          >
            <item.icon size={20} />
          </button>
        ))}
        {/* Settings button is always at the end on mobile nav for quick access */}
        <button
          onClick={() => setActiveView('settings')}
          className={`flex flex-col items-center gap-1 p-2.5 rounded-xl transition-all ${
            activeView === 'settings' ? 'bg-slate-900 text-white shadow-lg scale-110 -translate-y-1' : 'text-slate-400'
          }`}
        >
          <Settings size={20} />
        </button>
      </nav>
    </div>
  );
};

export default Layout;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Loader2, UserPlus2, Search, Edit, 
  Trash2, X, User as UserIcon, Save, SearchX, 
  School, Fingerprint, Lock, Info, 
  CheckCircle2, AlertCircle, RefreshCw, ChevronRight, UserCircle,
  Zap, UserCheck, ShieldCheck, AlertTriangle, Filter,
  Mail, Calendar, GraduationCap, LayoutGrid, UserCog, Key, Send,
  Eye, EyeOff, Clipboard
} from 'lucide-react';
import { auth, firestore } from '../../firebase';
import { collection, query, where, onSnapshot } from "firebase/firestore";
import { sendPasswordResetEmail } from "firebase/auth";
import { db } from '../../App.tsx';
import { User, ClassRoom } from '../../types.ts';

interface ManageStudentsTabProps {
  triggerConfirm: any;
  classes: ClassRoom[];
}

const ManageStudentsTab: React.FC<ManageStudentsTabProps> = ({ triggerConfirm, classes }) => {
  const [students, setStudents] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [isResetting, setIsResetting] = useState(false);
  const [showFormPassword, setShowFormPassword] = useState(false);
  const [search, setSearch] = useState('');
  const [classFilter, setClassFilter] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [visiblePasswords, setVisiblePasswords] = useState<Set<string>>(new Set());

  const [form, setForm] = useState<Partial<User>>({ 
    name: '', 
    username: '', 
    classId: '',
    avatar: '',
    password: '',
    status: 'ACTIVE'
  });

  // Urutkan kelas dari terkecil ke terbesar secara alfanumerik (7, 8, 9, 10...)
  const sortedClasses = useMemo(() => {
    return [...classes].sort((a, b) => 
      a.name.localeCompare(b.name, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [classes]);

  useEffect(() => {
    setLoading(true);
    const q = query(collection(firestore, "users"), where("role", "==", "STUDENT"));

    const unsubscribe = onSnapshot(q, (snapshot) => {
      const studentList: User[] = [];
      snapshot.forEach((doc) => {
        const data = doc.data() as User;
        if (data.status === 'ACTIVE') {
          studentList.push({ id: doc.id, ...data });
        }
      });
      setStudents(studentList);
      setLoading(false);
    }, (error) => {
      console.error("Error listening to students:", error);
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const filteredStudents = useMemo(() => students.filter(s => {
    const matchSearch = (s.name || '').toLowerCase().includes(search.toLowerCase()) || 
                        (s.username || '').toLowerCase().includes(search.toLowerCase());
    const matchClass = !classFilter || s.classId === classFilter;
    return matchSearch && matchClass;
  }), [students, search, classFilter]);

  const togglePasswordVisibility = (id: string) => {
    const newVisible = new Set(visiblePasswords);
    if (newVisible.has(id)) {
      newVisible.delete(id);
    } else {
      newVisible.add(id);
    }
    setVisiblePasswords(newVisible);
  };

  const handleSave = async () => {
    if (!form.name || !form.username || !form.classId) {
      alert("Mohon lengkapi Nama Lengkap, Username, dan Pilihan Kelas.");
      return;
    }

    setIsSaving(true);
    const studentData = { 
      ...form, 
      id: form.id || `std_${Date.now()}`, 
      role: 'STUDENT', 
      avatar: form.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${form.username || 'default'}`, 
      status: 'ACTIVE',
      createdAt: form.createdAt || new Date().toLocaleString('id-ID')
    } as User;

    try {
      if (form.id) {
        await db.update('users', form.id, studentData);
      } else {
        await db.add('users', studentData);
      }
      setShowModal(false);
    } catch (err) {
      alert("Gagal menyimpan data siswa ke Cloud.");
    } finally {
      setIsSaving(false);
    }
  };

  const handleResetPassword = async () => {
    if (!form.id || !form.username) return;

    const studentEmail = `${form.username}@alirsyad.sch.id`;

    triggerConfirm(
      "Kirim Link Reset Password?",
      `Sistem akan mengirimkan link pemulihan password ke email cloud siswa: ${studentEmail}. Password baru akan dicatat sebagai '123456' sebagai referensi sementara.`,
      async () => {
        setIsResetting(true);
        try {
          await sendPasswordResetEmail(auth, studentEmail);
          await db.update('users', form.id!, { 
            password: '123456',
            lastPasswordResetRequested: new Date().toLocaleString('id-ID')
          });
          setForm(prev => ({ ...prev, password: '123456' }));
          alert(`Berhasil! Link reset terkirim. Password referensi diubah ke: 123456`);
        } catch (err: any) {
          alert("Gagal: " + (err.message || "Pastikan akun terdaftar."));
        } finally {
          setIsResetting(false);
        }
      },
      'warning'
    );
  };

  const handleDelete = (id: string, name: string) => {
    triggerConfirm(
      `Hapus Profil Siswa?`, 
      `Semua data Cloud untuk "${name}" akan dihapus permanen.`, 
      async () => {
        try {
          await db.delete('users', id);
        } catch (err) {
          alert("Gagal menghapus data.");
        }
      }
    );
  };

  if (loading) return (
    <div className="py-32 flex flex-col items-center justify-center gap-4 text-black">
      <Loader2 className="animate-spin text-blue-600" size={48} />
      <p className="text-slate-400 font-black text-[10px] uppercase tracking-widest">Sinkronisasi Database Siswa...</p>
    </div>
  );

  return (
    <div className="space-y-8 text-black animate-in fade-in duration-500 pb-24">
      {/* Header & Filter Panel */}
      <section className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm space-y-8 relative overflow-hidden">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
          <div className="flex items-center gap-5">
            <div className="w-16 h-16 bg-blue-50 text-blue-600 rounded-[1.5rem] flex items-center justify-center shadow-inner">
              <GraduationCap size={32} />
            </div>
            <div>
              <h3 className="text-3xl font-black text-slate-800 tracking-tight">Database Siswa</h3>
              <p className="text-slate-500 font-medium text-sm mt-1">Mengelola {students.length} profil akademik cloud aktif.</p>
            </div>
          </div>
          <button 
            onClick={() => { setForm({ name: '', username: '', classId: '', avatar: '', password: '', status: 'ACTIVE' }); setShowModal(true); setShowFormPassword(false); }} 
            className="group px-8 py-4 bg-blue-600 text-white rounded-2xl font-black text-[11px] uppercase tracking-widest flex items-center justify-center gap-3 shadow-xl hover:bg-slate-900 transition-all active:scale-95"
          >
            <UserPlus2 size={20} /> Tambah Siswa Baru
          </button>
        </div>

        <div className="flex flex-col md:flex-row gap-4">
          <div className="flex-1 relative group">
            <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-blue-500 transition-colors" size={20} />
            <input 
              type="text" 
              placeholder="Cari berdasarkan nama atau username..." 
              value={search} 
              onChange={e => setSearch(e.target.value)} 
              className="w-full pl-14 pr-6 py-4 bg-slate-50 border-2 border-transparent rounded-2xl font-bold text-sm outline-none focus:bg-white focus:border-blue-500/10 transition-all shadow-inner" 
            />
          </div>
          <div className="w-full md:w-64 relative">
             <Filter className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
             <select 
               value={classFilter} 
               onChange={e => setClassFilter(e.target.value)}
               className="w-full pl-14 pr-6 py-4 bg-slate-50 border-2 border-transparent rounded-2xl font-black text-[10px] uppercase tracking-widest appearance-none outline-none focus:bg-white focus:border-blue-500/10 transition-all cursor-pointer shadow-inner"
             >
               <option value="">Semua Kelas</option>
               {sortedClasses.map(c => <option key={c.id} value={c.name}>Kelas {c.name}</option>)}
             </select>
          </div>
        </div>
      </section>

      {/* Grid Siswa */}
      {filteredStudents.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 xl:grid-cols-5 gap-6">
          {filteredStudents.map(s => (
            <div key={s.id} className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm flex flex-col items-center text-center relative group hover:shadow-2xl hover:-translate-y-2 transition-all duration-500 overflow-hidden">
              <div className="absolute top-4 right-4 flex gap-1.5 opacity-0 group-hover:opacity-100 transition-all z-10">
                <button onClick={() => { setForm(s); setShowModal(true); setShowFormPassword(false); }} className="p-3 bg-white text-blue-600 rounded-xl hover:bg-blue-600 hover:text-white transition-all shadow-lg border border-slate-50"><Edit size={16}/></button>
                <button onClick={() => handleDelete(s.id, s.name)} className="p-3 bg-white text-rose-600 rounded-xl hover:bg-rose-600 hover:text-white transition-all shadow-lg border border-slate-50"><Trash2 size={16}/></button>
              </div>

              <div className="relative mb-6">
                <img 
                  src={s.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${s.username}`} 
                  className="w-24 h-24 rounded-[2.5rem] border-4 border-white bg-slate-50 shadow-xl object-cover group-hover:scale-105 transition-transform duration-500" 
                  alt={s.name} 
                />
                <div className="absolute -bottom-1 -right-1 bg-emerald-500 p-2 rounded-full border-4 border-white shadow-lg">
                  <UserCheck size={12} className="text-white" />
                </div>
              </div>

              <h4 className="font-black text-slate-800 text-lg line-clamp-1 leading-tight">{s.name}</h4>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mt-2">@{s.username}</p>

              {/* Display Password on Card */}
              <div className="mt-4 w-full p-4 bg-slate-50 rounded-2xl flex items-center justify-between gap-2 border border-slate-100 group-hover:bg-blue-50 transition-colors">
                <div className="text-left overflow-hidden">
                   <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Sandi Cloud</p>
                   <p className="text-xs font-mono font-black text-slate-700 truncate">
                     {visiblePasswords.has(s.id) ? (s.password || '123456') : '••••••••'}
                   </p>
                </div>
                <button 
                  onClick={() => togglePasswordVisibility(s.id)}
                  className="p-2 text-slate-400 hover:text-blue-600 transition-colors"
                  title="Lihat Password"
                >
                  {visiblePasswords.has(s.id) ? <EyeOff size={16} /> : <Eye size={16} />}
                </button>
              </div>

              <div className="w-full pt-4 mt-2 border-t border-slate-50 flex items-center justify-center gap-3">
                 <div className="px-4 py-1.5 bg-blue-50 text-blue-600 rounded-full flex items-center gap-2">
                    <School size={12} />
                    <span className="text-[10px] font-black uppercase tracking-tight">Kelas {s.classId || 'N/A'}</span>
                 </div>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="bg-white rounded-[3rem] border-2 border-dashed border-slate-200 p-20 flex flex-col items-center text-center">
          <div className="w-20 h-20 bg-slate-50 text-slate-300 rounded-3xl flex items-center justify-center mb-6">
            <SearchX size={40} />
          </div>
          <h4 className="text-xl font-black text-slate-400">Database Kosong</h4>
          <p className="text-slate-400 font-medium text-sm max-w-xs mt-2 italic">"{search}" tidak cocok dengan data siswa mana pun.</p>
        </div>
      )}

      {/* Modal Tambah/Edit */}
      {showModal && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-md z-[100] flex items-center justify-center p-4 md:p-6 overflow-hidden animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-2xl rounded-[3.5rem] shadow-2xl relative flex flex-col max-h-[90vh] overflow-hidden">
            {/* Modal Header */}
            <div className="p-8 md:p-10 border-b border-slate-50 flex items-center justify-between shrink-0 bg-white">
               <div className="flex items-center gap-5">
                  <div className={`w-14 h-14 rounded-2xl flex items-center justify-center shadow-lg shadow-blue-100 ${form.id ? 'bg-indigo-600 text-white' : 'bg-blue-600 text-white'}`}>
                    {form.id ? <UserCog size={28} /> : <UserPlus2 size={28} />}
                  </div>
                  <div>
                    <h3 className="text-2xl font-black text-slate-800 leading-none">{form.id ? 'Edit Profil' : 'Registrasi Siswa'}</h3>
                    <p className="text-slate-400 font-bold text-[10px] uppercase tracking-widest mt-2">Identitas Cloud Siswa</p>
                  </div>
               </div>
               <button onClick={() => setShowModal(false)} className="p-3 bg-slate-50 text-slate-400 rounded-2xl hover:bg-rose-50 hover:text-rose-500 transition-all">
                  <X size={24} />
               </button>
            </div>

            {/* Modal Body */}
            <div className="flex-1 overflow-y-auto p-8 md:p-10 space-y-10 scrollbar-hide">
              <div className="flex flex-col items-center justify-center py-6 bg-slate-50 rounded-[2.5rem] border border-slate-100 shadow-inner">
                <img 
                  src={form.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${form.username || 'default'}`} 
                  className="w-24 h-24 rounded-full border-4 border-white shadow-xl bg-white mb-4" 
                  alt="Avatar Preview" 
                />
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Avatar Preview Cloud</p>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-3">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nama Lengkap Siswa</label>
                  <div className="relative group">
                    <UserIcon className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
                    <input 
                      value={form.name} 
                      onChange={e => setForm({...form, name: e.target.value})} 
                      placeholder="Nama lengkap..." 
                      className="w-full p-5 pl-14 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none font-bold text-slate-800 focus:border-blue-500 focus:bg-white transition-all shadow-inner" 
                    />
                  </div>
                </div>

                <div className="space-y-3">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Username (Login ID)</label>
                  <div className="relative group">
                    <Fingerprint className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
                    <input 
                      value={form.username} 
                      onChange={e => setForm({...form, username: e.target.value.toLowerCase().replace(/\s/g, '')})} 
                      placeholder="Username..." 
                      className="w-full p-5 pl-14 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none font-bold text-slate-800 focus:border-blue-500 focus:bg-white transition-all shadow-inner" 
                    />
                  </div>
                </div>

                <div className="space-y-3">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Pilih Kelas</label>
                  <div className="relative group">
                    <School className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
                    <select 
                      value={form.classId} 
                      onChange={e => setForm({...form, classId: e.target.value})}
                      className="w-full p-5 pl-14 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none font-bold text-slate-800 focus:border-blue-500 focus:bg-white transition-all shadow-inner appearance-none cursor-pointer"
                    >
                      <option value="">Pilih Kelas Siswa</option>
                      {sortedClasses.map(c => <option key={c.id} value={c.name}>Kelas {c.name}</option>)}
                    </select>
                  </div>
                </div>

                <div className="space-y-3">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Email Kredensial</label>
                  <div className="flex items-center p-5 bg-blue-50 rounded-2xl border border-blue-100 text-[11px] font-bold text-blue-600 gap-3">
                    <Mail size={16} />
                    <span>{form.username || 'username'}@alirsyad.sch.id</span>
                  </div>
                </div>

                {/* Password Field in Edit Modal */}
                <div className="space-y-3 col-span-1 md:col-span-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Kata Sandi (Referensi)</label>
                  <div className="relative group">
                    <Lock className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
                    <input 
                      type={showFormPassword ? 'text' : 'password'}
                      value={form.password || ''} 
                      onChange={e => setForm({...form, password: e.target.value})} 
                      placeholder="Isi password atau biarkan default" 
                      className="w-full p-5 pl-14 pr-14 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none font-black text-slate-800 focus:border-blue-500 focus:bg-white transition-all shadow-inner" 
                    />
                    <button 
                      type="button" 
                      onClick={() => setShowFormPassword(!showFormPassword)} 
                      className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 transition-colors"
                    >
                      {showFormPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                    </button>
                  </div>
                  <div className="flex items-center gap-2 p-3 bg-amber-50 rounded-xl border border-amber-100 mt-2">
                    <Info size={14} className="text-amber-500" />
                    <p className="text-[9px] text-amber-700 font-bold italic">Catatan: Password ini disimpan untuk memudahkan Admin membantu siswa. Disarankan meriset password jika siswa lupa akses.</p>
                  </div>
                </div>
              </div>

              {/* Reset Password Action Area */}
              {form.id && (
