        <button onClick={() => { setForm({ title: '', description: '', type: 'link', content: '', targetClassIds: [] }); setShowModal(true); }} className="px-8 py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-3">
          <Plus size={20}/> Materi Baru
