import React, { useState, useEffect, useMemo } from 'react';
import { 
  Loader2, Plus, Search, ClipboardList, Calendar, Edit, Trash2, X, Save, 
  Globe, Youtube, FileText, Link as LinkIcon, ToggleRight, ToggleLeft
} from 'lucide-react';
import { db } from '../../App.tsx';
import { Task, ClassRoom, User } from '../../types.ts';
import { notifyStudents } from '../../utils/helpers.ts';

interface ManageTasksTabProps {
  triggerConfirm: any;
  classes: ClassRoom[];
  currentUser: User;
}

const ManageTasksTab: React.FC<ManageTasksTabProps> = ({ triggerConfirm, classes, currentUser }) => {
  const [items, setItems] = useState<Task[]>([]);
  const [showModal, setShowModal] = useState(false);
  const [loading, setLoading] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [search, setSearch] = useState('');
  const [form, setForm] = useState<Partial<Task>>({ 
    title: '', description: '', content: '', targetClassIds: [], 
    dueDate: '', isSubmissionEnabled: true, type: 'link' 
  });

  useEffect(() => { loadData(); }, []);

  const loadData = async () => {
    setLoading(true);
    try {
      const saved = await db.get('elearning_tasks');
      const all = Array.isArray(saved) ? saved : [];
      setItems(currentUser.username === 'admin' ? all : all.filter((t: any) => t.authorId === currentUser.id));
    } catch (err) { console.error(err); }
    finally { setLoading(false); }
  };

  const handleSave = async () => {
    if (!form.title || !form.dueDate || !form.content) { alert("Lengkapi data!"); return; }
    setIsSaving(true);
    const newItem: Task = { 
      ...form, 
      id: form.id || `tsk_${Date.now()}`, 
      subject: currentUser.subject || 'Umum',
      authorId: currentUser.id,
      targetClassIds: Array.isArray(form.targetClassIds) ? form.targetClassIds : [],
      createdAt: form.createdAt || new Date().toLocaleString('id-ID'),
    } as Task;

    try {
      if (!form.id) {
        await db.add('elearning_tasks', newItem);
        setItems([newItem, ...items]);
        await notifyStudents(newItem.targetClassIds, `Tugas ${newItem.subject} Baru!`, `${currentUser.name} memberi tugas: ${newItem.title}`, "task");
      } else {
        await db.update('elearning_tasks', newItem.id, newItem);
        setItems(items.map(it => it.id === newItem.id ? newItem : it));
      }
      setShowModal(false);
    } catch (err) { alert("Gagal."); }
    finally { setIsSaving(false); }
  };

  if (loading) return <div className="py-32 flex justify-center"><Loader2 className="animate-spin text-purple-600" size={48} /></div>;

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-24">
      <section className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm flex flex-col md:flex-row justify-between items-center gap-6">
        <div>
           <h3 className="text-3xl font-black text-slate-800">Tugas {currentUser.subject}</h3>
           <p className="text-slate-500 font-medium">Evaluasi akademik untuk mata pelajaran Anda.</p>
        </div>
        <button onClick={() => { setForm({ title: '', description: '', content: '', targetClassIds: [], dueDate: '', isSubmissionEnabled: true, type: 'link' }); setShowModal(true); }} className="px-8 py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-3">
          <Plus size={20}/> Tambah Tugas
        </button>
      </section>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
        {items.map(it => (
          <div key={it.id} className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col group hover:shadow-2xl hover:-translate-y-2 transition-all duration-500">
             <div className="h-24 bg-purple-50 flex items-center justify-center relative">
                <ClipboardList size={40} className="text-purple-600 opacity-20" />
                <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-all">
                  <button onClick={() => { setForm(it); setShowModal(true); }} className="p-2.5 bg-white text-slate-600 rounded-xl hover:bg-slate-900 hover:text-white shadow-xl"><Edit size={14}/></button>
                  <button onClick={() => triggerConfirm("Hapus?", "Data hilang!", () => db.delete('elearning_tasks', it.id).then(() => setItems(items.filter(x => x.id !== it.id))))} className="p-2.5 bg-white text-rose-500 rounded-xl hover:bg-rose-500 hover:text-white shadow-xl"><Trash2 size={14}/></button>
                </div>
             </div>
             <div className="p-7">
                <h4 className="font-black text-slate-800 text-base leading-tight mb-2">{it.title}</h4>
                <div className="flex items-center gap-2 mb-4 text-slate-400">
                  <Calendar size={12} />
                  <span className="text-[10px] font-black uppercase tracking-widest">Tenggat: {it.dueDate}</span>
                </div>
                <div className="flex flex-wrap gap-1.5 mt-auto pt-4 border-t border-slate-50">
                  {it.targetClassIds.map(cid => <span key={cid} className="px-2 py-0.5 bg-slate-50 text-slate-400 text-[8px] font-black rounded-lg border border-slate-100">{cid}</span>)}
                </div>
             </div>
          </div>
        ))}
      </div>

      {showModal && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-md z-[100] flex items-center justify-center p-6 overflow-hidden">
           <div className="bg-white w-full max-w-2xl rounded-[3.5rem] shadow-2xl flex flex-col max-h-[90vh] overflow-hidden">
              <div className="p-8 border-b border-slate-50 flex items-center justify-between">
                 <h3 className="text-2xl font-black text-slate-800">Form Tugas {currentUser.subject}</h3>
                 <button onClick={() => setShowModal(false)}><X size={24} /></button>
              </div>
              <div className="p-10 space-y-6 overflow-y-auto">
                 <input value={form.title} onChange={e => setForm({...form, title: e.target.value})} placeholder="Judul Tugas..." className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold" />
                 <div className="grid grid-cols-2 gap-4">
                    <input type="date" value={form.dueDate} onChange={e => setForm({...form, dueDate: e.target.value})} className="p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold" />
                    <button onClick={() => setForm({...form, isSubmissionEnabled: !form.isSubmissionEnabled})} className={`p-5 rounded-2xl font-black text-[10px] uppercase border-2 flex items-center justify-between ${form.isSubmissionEnabled ? 'bg-emerald-50 border-emerald-100 text-emerald-600' : 'bg-rose-50 border-rose-100 text-rose-600'}`}>
                       {form.isSubmissionEnabled ? 'Upload Aktif' : 'Upload Mati'} {form.isSubmissionEnabled ? <ToggleRight size={24}/> : <ToggleLeft size={24}/>}
                    </button>
                 </div>
                 <textarea value={form.description} onChange={e => setForm({...form, description: e.target.value})} placeholder="Instruksi..." className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold h-24" />
                 <input value={form.content} onChange={e => setForm({...form, content: e.target.value})} placeholder="URL Sumber/Template..." className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold" />
                 <div className="space-y-3">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Target Kelas</p>
                    <div className="flex flex-wrap gap-2">
                       {classes.filter(c => (currentUser.assignedClassIds || []).includes(c.name) || currentUser.username === 'admin').map(c => {
                          const isSelected = (form.targetClassIds || []).includes(c.name);
                          return (
                             <button 
                                key={c.id} 
                                onClick={() => {
                                   const cur = form.targetClassIds || [];
                                   setForm({...form, targetClassIds: isSelected ? cur.filter(x => x !== c.name) : [...cur, c.name]});
                                }} 
                                className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${isSelected ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}
                             >Kelas {c.name}</button>
                          );
                       })}
                    </div>
                 </div>
              </div>
              <div className="p-8 border-t border-slate-50 flex gap-4">
                 <button onClick={() => setShowModal(false)} className="flex-1 py-4 bg-slate-50 text-slate-500 rounded-2xl font-black text-xs uppercase">Batal</button>
                 <button onClick={handleSave} disabled={isSaving} className="flex-[2] py-4 bg-purple-600 text-white rounded-2xl font-black text-xs uppercase shadow-xl">
                   {isSaving ? "Menyimpan..." : "Simpan Penugasan"}
                 </button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

