      </section>

      {/* Subjects Grid */}
      <section className="space-y-6">
        <div className="flex items-center gap-3 px-2">
           <div className="w-2 h-8 bg-indigo-500 rounded-full"></div>
           <h3 className="text-2xl font-black text-slate-800 tracking-tight">Mata Pelajaran Kamu</h3>
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
           {availableSubjects.map((subject, i) => (
             <div key={i} className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm hover:shadow-2xl hover:-translate-y-2 transition-all duration-500 group relative overflow-hidden">
                <div className="absolute -right-4 -top-4 w-24 h-24 bg-indigo-50 rounded-full opacity-50 group-hover:scale-150 transition-transform"></div>
                <div className="relative z-10 space-y-4">
                   <div className="w-14 h-14 bg-indigo-600 text-white rounded-2xl flex items-center justify-center shadow-lg group-hover:rotate-12 transition-transform">
                      <BookOpen size={28} />
                   </div>
                   <div>
                      <h4 className="text-xl font-black text-slate-800 leading-tight group-hover:text-indigo-600 transition-colors">{subject}</h4>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">E-Learning Module</p>
