import React, { useState, useEffect } from 'react';
import { BarChart3, BookOpen, ClipboardList, Users, School, Settings, UserPlus, CheckCircle, AlertTriangle, Briefcase } from 'lucide-react';
import Layout from '../components/Layout.tsx';
import { User, SiteSettings, ClassRoom } from '../types.ts';
import { db } from '../App.tsx';
import { firestore } from '../firebase';
import { collection, query, where, onSnapshot } from "firebase/firestore";

import OverviewTab from './admin/OverviewTab.tsx';
import ConfirmRegistrationsTab from './admin/ConfirmRegistrationsTab.tsx';
import ManageMaterialsTab from './admin/ManageMaterialsTab.tsx';
import ManageTasksTab from './admin/ManageTasksTab.tsx';
import GradesTab from './admin/GradesTab.tsx';
import ManageStudentsTab from './admin/ManageStudentsTab.tsx';
import ManageClassesTab from './admin/ManageClassesTab.tsx';
import SettingsTab from './admin/SettingsTab.tsx';
import ManageTeachersTab from './admin/ManageTeachersTab.tsx';

interface AdminDashboardProps {
  user: User;
  onLogout: () => void;
  settings: SiteSettings;
  setSettings: React.Dispatch<React.SetStateAction<SiteSettings>>;
  onUpdateUser?: (u: User) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ user, onLogout, settings, setSettings, onUpdateUser }) => {
  const [activeView, setActiveView] = useState('overview');
  const [notifications, setNotifications] = useState<any[]>([]);
  const [classes, setClasses] = useState<ClassRoom[]>([]);
  const [confirmModal, setConfirmModal] = useState<{
    isOpen: boolean;
    title: string;
    message: string;
    onConfirm: () => void;
    type: 'danger' | 'warning';
  }>({
    isOpen: false,
    title: '',
    message: '',
    onConfirm: () => {},
    type: 'danger'
  });

  useEffect(() => {
    const qNotifs = query(
      collection(firestore, 'elearning_notifications'), 
      where('userId', '==', user.id)
    );

    const unsubscribeNotifs = onSnapshot(qNotifs, (snapshot) => {
      const notifList = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      setNotifications(notifList);
    });

    const fetchClasses = async () => {
      const c = await db.get('elearning_classes');
      setClasses(Array.isArray(c) ? c : []);
    };
    fetchClasses();

    return () => {
      unsubscribeNotifs();
    };
  }, [user.id]);

  const handleMarkAsRead = async (id: string) => {
    const notif = notifications.find(n => n.id === id);
    if (notif) {
      await db.update('elearning_notifications', id, { ...notif, read: true });
    }
  };

  const handleMarkAllRead = async () => {
    const updated = notifications.filter(n => !n.read).map(n => ({ ...n, read: true }));
    if (updated.length > 0) {
      await db.saveAll('elearning_notifications', updated);
    }
  };

  // Identifikasi apakah ini Admin Utama atau Guru Mapel
  const isSuperAdmin = user.username === 'admin';

  // Sembunyikan menu manajemen sistem untuk Guru Mapel lain
  const sidebarItems = isSuperAdmin 
    ? [
        { id: 'overview', label: 'Ringkasan', icon: BarChart3 },
        { id: 'confirmations', label: 'Konfirmasi Siswa', icon: UserPlus },
        { id: 'teachers', label: 'Kelola Guru', icon: Briefcase },
        { id: 'materials', label: 'Kelola Materi', icon: BookOpen },
        { id: 'tasks', label: 'Kelola Tugas', icon: ClipboardList },
        { id: 'grades', label: 'Nilai Tugas', icon: CheckCircle },
        { id: 'students', label: 'Kelola Siswa', icon: Users },
        { id: 'classes', label: 'Kelola Kelas', icon: School },
        { id: 'settings', label: 'Pengaturan', icon: Settings },
      ]
    : [
        { id: 'overview', label: 'Ringkasan', icon: BarChart3 },
        { id: 'materials', label: 'Kelola Materi', icon: BookOpen },
        { id: 'tasks', label: 'Kelola Tugas', icon: ClipboardList },
        { id: 'grades', label: 'Nilai Tugas', icon: CheckCircle },
        { id: 'settings', label: 'Profil Saya', icon: Settings },
      ];

  const triggerConfirm = (title: string, message: string, onConfirm: () => void, type: 'danger' | 'warning' = 'danger') => {
    setConfirmModal({ isOpen: true, title, message, onConfirm, type });
  };

  const closeConfirm = () => setConfirmModal(prev => ({ ...prev, isOpen: false }));

  const renderContent = () => {
    switch (activeView) {
      case 'overview': return <OverviewTab setActiveView={setActiveView} currentUser={user} />;
      case 'confirmations': return isSuperAdmin ? <ConfirmRegistrationsTab triggerConfirm={triggerConfirm} /> : null;
      case 'teachers': return isSuperAdmin ? <ManageTeachersTab triggerConfirm={triggerConfirm} classes={classes} /> : null;
      case 'materials': return <ManageMaterialsTab triggerConfirm={triggerConfirm} classes={classes} currentUser={user} />;
      case 'tasks': return <ManageTasksTab triggerConfirm={triggerConfirm} classes={classes} currentUser={user} />;
      case 'grades': return <GradesTab triggerConfirm={triggerConfirm} classes={classes} currentUser={user} />;
      case 'students': return isSuperAdmin ? <ManageStudentsTab triggerConfirm={triggerConfirm} classes={classes} /> : null;
      case 'classes': return isSuperAdmin ? <ManageClassesTab triggerConfirm={triggerConfirm} classes={classes} setClasses={setClasses} /> : null;
      case 'settings': return <SettingsTab settings={settings} setSettings={setSettings} user={user} onUpdateUser={onUpdateUser!} />;
      default: return <OverviewTab setActiveView={setActiveView} currentUser={user} />;
    }
  };

  return (
    <Layout 
      user={user} 
      onLogout={onLogout} 
      sidebarItems={sidebarItems} 
      activeView={activeView} 
      setActiveView={setActiveView}
      logoUrl={settings.logoUrl}
      siteName={settings.siteName}
      notifications={notifications}
      onMarkAsRead={handleMarkAsRead}
      onMarkAllAsRead={handleMarkAllRead}
    >
      {renderContent()}

      {confirmModal.isOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-6 text-black">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] p-10 shadow-2xl animate-in zoom-in-95 duration-200 text-center">
            <div className={`w-20 h-20 mx-auto rounded-3xl flex items-center justify-center mb-6 ${confirmModal.type === 'danger' ? 'bg-red-50 text-red-500' : 'bg-orange-50 text-orange-500'}`}>
              <AlertTriangle size={40} className={confirmModal.type === 'danger' ? 'text-red-500' : 'text-orange-500'} />
            </div>
            <h3 className="text-2xl font-black text-slate-800 mb-2">{confirmModal.title}</h3>
            <p className="text-slate-500 font-medium text-sm leading-relaxed mb-10">{confirmModal.message}</p>
            <div className="flex gap-4">
              <button onClick={closeConfirm} className="flex-1 py-4 bg-slate-50 text-slate-500 rounded-2xl font-black text-sm hover:bg-slate-100 transition-all">Batal</button>
              <button onClick={() => { confirmModal.onConfirm(); closeConfirm(); }} className={`flex-1 py-4 text-white rounded-2xl font-black text-sm shadow-xl transition-all ${confirmModal.type === 'danger' ? 'bg-red-500 hover:bg-red-600' : 'bg-orange-500 hover:bg-orange-600'}`}>Ya, Lanjutkan</button>
            </div>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default AdminDashboard;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Loader2, History, Clock, ClipboardCheck, Search, Filter, 
  ClipboardList, ExternalLink, GraduationCap, X, Eye, 
  Award, Star, MessageCircle, Save, MessageSquare, Printer,
  ChevronDown, ArrowDown, Trash2, RotateCcw, CheckSquare, Square
} from 'lucide-react';
import { db } from '../../App.tsx';
import { Submission, Task, User, ClassRoom } from '../../types.ts';
import { notifyStudents } from '../../utils/helpers.ts';

interface GradesTabProps {
  triggerConfirm: any;
  classes: ClassRoom[];
  currentUser: User;
}

const GradesTab: React.FC<GradesTabProps> = ({ triggerConfirm, classes, currentUser }) => {
  const [subs, setSubs] = useState<Submission[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [gradeModal, setGradeModal] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [search, setSearch] = useState('');
  const [classFilter, setClassFilter] = useState('');
  const [taskFilter, setTaskFilter] = useState('');
  const [displayLimit, setDisplayLimit] = useState(10);

  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  useEffect(() => {
    const fetch = async () => {
      setLoading(true);
      try {
        const [s, t, u] = await Promise.all([
          db.get('elearning_submissions'), 
          db.get('elearning_tasks'), 
          db.get('users')
        ]);

        const allTasks = Array.isArray(t) ? t : [];
        const allSubs = Array.isArray(s) ? s : [];

        // Filter Tugas: Jika bukan super admin, hanya ambil tugas dari mapel guru ini
        const relevantTasks = currentUser.username === 'admin' 
          ? allTasks 
          : allTasks.filter(task => task.authorId === currentUser.id);

        const relevantTaskIds = new Set(relevantTasks.map(t => t.id));

        // Filter Submissions: Hanya ambil pengumpulan yang berkaitan dengan tugas di atas
        const relevantSubs = allSubs.filter(sub => relevantTaskIds.has(sub.taskId));

        setTasks(relevantTasks);
        setSubs(relevantSubs);
        setAllUsers(Array.isArray(u) ? u : []);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetch();
  }, [currentUser]);

  const sortedClasses = useMemo(() => {
    return [...classes].sort((a, b) => 
      a.name.localeCompare(b.name, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [classes]);

  const filteredSubs = useMemo(() => {
    const filtered = subs.filter(s => {
      const student = allUsers.find(st => st.id === s.studentId);
      const task = tasks.find(t => t.id === s.taskId);

      const matchSearch = (student?.name || '').toLowerCase().includes(search.toLowerCase()) || 
                          (task?.title || '').toLowerCase().includes(search.toLowerCase());
      const matchClass = !classFilter || student?.classId === classFilter;
      const matchTask = !taskFilter || s.taskId === taskFilter;

      return matchSearch && matchClass && matchTask;
    });

    return filtered.sort((a, b) => {
      const studentA = allUsers.find(st => st.id === a.studentId);
      const studentB = allUsers.find(st => st.id === b.studentId);
      const classNameA = studentA?.classId || '';
      const classNameB = studentB?.classId || '';
      const classCompare = classNameA.localeCompare(classNameB, undefined, { numeric: true, sensitivity: 'base' });
      if (classCompare !== 0) return classCompare;
      const nameA = studentA?.name || '';
      const nameB = studentB?.name || '';
      return nameA.localeCompare(nameB);
    });
  }, [subs, allUsers, tasks, search, classFilter, taskFilter]);

  const displayedSubs = useMemo(() => {
    return filteredSubs.slice(0, displayLimit);
  }, [filteredSubs, displayLimit]);

  const stats = useMemo(() => ({
    total: filteredSubs.length,
    graded: filteredSubs.filter(s => s.grade !== undefined && s.grade !== null).length,
    pending: filteredSubs.filter(s => s.grade === undefined || s.grade === null).length
  }), [filteredSubs]);

  const toggleSelectAll = () => {
    if (selectedIds.size === displayedSubs.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(displayedSubs.map(s => s.id)));
    }
  };

  const toggleSelect = (id: string) => {
    const newSelected = new Set(selectedIds);
    if (newSelected.has(id)) newSelected.delete(id);
    else newSelected.add(id);
    setSelectedIds(newSelected);
  };

  const handleBulkDelete = () => {
    if (selectedIds.size === 0) return;
    triggerConfirm(
      `Reset Status Tugas?`,
      `Menghapus ${selectedIds.size} data pengumpulan akan mengizinkan siswa mengirim ulang tugas.`,
      async () => {
        try {
          const idsArray = Array.from(selectedIds);
          await Promise.all(idsArray.map((id: string) => db.delete('elearning_submissions', id)));
          setSubs(prev => prev.filter(s => !selectedIds.has(s.id)));
          setSelectedIds(new Set());
        } catch (err) { alert("Gagal menghapus."); }
      }
    );
  };

  const handlePrint = () => {
    const printWindow = window.open('', '_blank');
    if (!printWindow) return;
    let tableRows = '';
    filteredSubs.forEach(s => {
      const student = allUsers.find(st => st.id === s.studentId);
      const task = tasks.find(t => t.id === s.taskId);
      tableRows += `<tr><td>${student?.name || 'N/A'}</td><td>${task?.title || 'N/A'} (Kelas ${student?.classId || 'N/A'})</td><td style="text-align:center;">${s.grade ?? '--'}</td></tr>`;
    });
    printWindow.document.write(`<html><body><h1>Rekap Nilai ${currentUser.subject}</h1><table><thead><tr><th>Nama</th><th>Tugas</th><th>Skor</th></tr></thead><tbody>${tableRows}</tbody></table></body><script>window.onload=function(){window.print();window.close();}</script></html>`);
    printWindow.document.close();
  };

  const handleGrade = async () => {
    if (gradeModal.grade === "" || gradeModal.grade < 0 || gradeModal.grade > 100) { alert("Nilai tidak valid."); return; }
    try {
      const updated = { ...gradeModal, grade: Number(gradeModal.grade), feedback: gradeModal.feedback || '' };
      await db.update('elearning_submissions', gradeModal.id, updated);
      setSubs(subs.map(s => s.id === gradeModal.id ? updated : s));
      notifyStudents([], "Tugas Dinilai!", `Skor: ${gradeModal.grade}`, "grade", gradeModal.studentId);
      setGradeModal(null);
    } catch (err) { alert("Gagal."); }
  };

  if (loading) return <div className="py-32 flex flex-col items-center justify-center"><Loader2 className="animate-spin text-indigo-600" size={48} /></div>;

  return (
    <div className="space-y-8 text-black pb-20">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {[
          { label: 'Tugas Masuk', val: stats.total, icon: History, col: 'text-blue-600', bg: 'bg-blue-50' },
          { label: 'Perlu Dinilai', val: stats.pending, icon: Clock, col: 'text-orange-600', bg: 'bg-orange-50' },
          { label: 'Selesai', val: stats.graded, icon: ClipboardCheck, col: 'text-emerald-600', bg: 'bg-emerald-50' },
        ].map((s, i) => (
          <div key={i} className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm flex items-center gap-6">
            <div className={`${s.bg} ${s.col} w-14 h-14 rounded-2xl flex items-center justify-center`}><s.icon size={28}/></div>
            <div>
              <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">{s.label}</p>
              <h4 className="text-3xl font-black text-slate-800">{s.val}</h4>
            </div>
          </div>
        ))}
      </div>

      <section className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm space-y-6">
        <div className="flex flex-col md:flex-row gap-4 items-end">
          <div className="flex-1 relative w-full">
            <input type="text" placeholder="Cari siswa atau tugas..." value={search} onChange={e => setSearch(e.target.value)} className="w-full pl-12 pr-6 py-4 bg-slate-50 rounded-2xl font-bold text-sm outline-none focus:bg-white border-2 border-transparent focus:border-indigo-100 transition-all" />
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
          </div>
          <select value={classFilter} onChange={e => setClassFilter(e.target.value)} className="w-full md:w-48 p-4 bg-slate-50 rounded-2xl font-black text-[10px] uppercase outline-none">
            <option value="">Semua Kelas</option>
            {sortedClasses.map(c => <option key={c.id} value={c.name}>Kelas {c.name}</option>)}
          </select>
          <div className="flex gap-2 w-full md:w-auto">
            <button onClick={handlePrint} className="flex-1 md:flex-none px-6 py-4 bg-white border-2 border-slate-100 rounded-2xl font-black text-[10px] uppercase flex items-center gap-2"><Printer size={18} /> Rekap</button>
            {selectedIds.size > 0 && <button onClick={handleBulkDelete} className="px-6 py-4 bg-rose-600 text-white rounded-2xl font-black text-[10px] uppercase flex items-center gap-2 animate-in slide-in-from-right"><RotateCcw size={18} /> Reset ({selectedIds.size})</button>}
          </div>
        </div>
      </section>

      <div className="bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50/50 uppercase text-[10px] font-black text-slate-400">
              <tr>
                <th className="px-10 py-6"><button onClick={toggleSelectAll}>{selectedIds.size === displayedSubs.length && displayedSubs.length > 0 ? <CheckSquare size={20} className="text-indigo-600" /> : <Square size={20} />}</button></th>
                <th className="px-4 py-6">Siswa</th>
                <th className="px-10 py-6">Tugas</th>
                <th className="px-10 py-6 text-center">Skor</th>
                <th className="px-10 py-6 text-right">Aksi</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {displayedSubs.map(s => {
                const student = allUsers.find(st => st.id === s.studentId);
                const task = tasks.find(t => t.id === s.taskId);
                const isGraded = s.grade !== undefined && s.grade !== null;
                return (
                  <tr key={s.id} className="hover:bg-slate-50/50 transition-colors">
                    <td className="px-10 py-6"><button onClick={() => toggleSelect(s.id)}>{selectedIds.has(s.id) ? <CheckSquare size={20} className="text-indigo-600" /> : <Square size={20} className="text-slate-200" />}</button></td>
                    <td className="px-4 py-6">
                      <div className="flex items-center gap-3">
                        <img src={student?.avatar} className="w-10 h-10 rounded-full bg-slate-100" />
                        <div><p className="font-black text-slate-800 text-sm">{student?.name}</p><p className="text-[9px] text-slate-400 font-bold uppercase">Kelas {student?.classId}</p></div>
                      </div>
                    </td>
                    <td className="px-10 py-6"><p className="font-bold text-slate-700">{task?.title}</p></td>
                    <td className="px-10 py-6 text-center"><span className={`text-2xl font-black ${isGraded ? 'text-indigo-600' : 'text-slate-200'}`}>{isGraded ? s.grade : '--'}</span></td>
                    <td className="px-10 py-6 text-right"><button onClick={() => setGradeModal(s)} className={`px-6 py-3 rounded-xl font-black text-[10px] uppercase ${isGraded ? 'bg-slate-100 text-slate-600' : 'bg-slate-900 text-white'}`}>{isGraded ? 'Edit' : 'Nilai'}</button></td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          {filteredSubs.length === 0 && <div className="py-20 text-center"><p className="text-slate-400 font-black text-xs uppercase tracking-widest">Tidak ada data untuk ditampilkan</p></div>}
      </div>

      {gradeModal && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[100] flex items-center justify-center p-6 text-black">
          <div className="bg-white w-full max-w-xl rounded-[3.5rem] shadow-2xl flex flex-col p-10 space-y-8 animate-in zoom-in-95">
             <div className="flex justify-between items-center"><h3 className="text-2xl font-black">Evaluasi Tugas</h3><button onClick={() => setGradeModal(null)}><X size={28}/></button></div>
             <div className="space-y-4">
                <p className="text-[10px] font-black uppercase text-slate-400">Tautan Hasil Kerja:</p>
                <a href={gradeModal.content} target="_blank" className="block p-4 bg-slate-50 border rounded-2xl font-bold text-indigo-600 truncate">{gradeModal.content}</a>
             </div>
             <div className="grid grid-cols-2 gap-4">
