                   <div>
                      <h4 className="text-xl font-black text-slate-800 leading-tight group-hover:text-indigo-600 transition-colors">{subject}</h4>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">E-Learning Module</p>
