import React, { useState, useMemo, useEffect } from 'react';
import { 
  FileText, ExternalLink, Search, Filter, 
  PlayCircle, Link as LinkIcon, Clock, Sparkles, 
  SearchX, ChevronRight, BookOpen, X, Info,
  Monitor, Globe, ArrowUpRight, Zap
} from 'lucide-react';

interface MaterialsTabProps {
  materials: any[];
  initialSubject?: string;
}

const MaterialsTab: React.FC<MaterialsTabProps> = ({ materials, initialSubject }) => {
  const [search, setSearch] = useState('');
  const [activeFilter, setActiveFilter] = useState('all');
  const [subjectFilter, setSubjectFilter] = useState(initialSubject || 'all');
  const [selectedMaterial, setSelectedMaterial] = useState<any | null>(null);

  // Ambil daftar mata pelajaran unik dari materi yang tersedia
  const subjects = useMemo(() => {
    return Array.from(new Set(materials.map(m => m.subject))).filter(Boolean);
  }, [materials]);

  useEffect(() => {
    if (initialSubject) {
      setSubjectFilter(initialSubject);
    }
  }, [initialSubject]);

  const filteredMaterials = useMemo(() => {
    return materials.filter(m => {
      const matchSearch = m.title.toLowerCase().includes(search.toLowerCase()) || 
                          m.description.toLowerCase().includes(search.toLowerCase());
      const matchType = activeFilter === 'all' || m.type === activeFilter;
      const matchSubject = subjectFilter === 'all' || m.subject === subjectFilter;
      return matchSearch && matchType && matchSubject;
    });
  }, [materials, search, activeFilter, subjectFilter]);

  const getTypeStyle = (type: string) => {
    switch(type) {
      case 'embed': return { bg: 'bg-purple-50', text: 'text-purple-600', icon: PlayCircle, label: 'Video' };
      case 'file': return { bg: 'bg-emerald-50', text: 'text-emerald-600', icon: FileText, label: 'Modul' };
      case 'link': return { bg: 'bg-blue-50', text: 'text-blue-600', icon: LinkIcon, label: 'Tautan' };
      default: return { bg: 'bg-slate-50', text: 'text-slate-600', icon: BookOpen, label: 'Materi' };
    }
  };

  const getEmbedUrl = (url: string) => {
    if (!url) return '';
    let embedUrl = url;

    if (url.includes('youtube.com/watch?v=')) {
      embedUrl = url.replace('watch?v=', 'embed/');
    } else if (url.includes('youtu.be/')) {
      embedUrl = 'https://www.youtube.com/embed/' + url.split('youtu.be/')[1];
    } else if (url.includes('docs.google.com')) {
      embedUrl = url.includes('?') ? `${url}&embedded=true` : `${url}?embedded=true`;
    } else if (url.includes('canva.com/design/')) {
      const baseUrl = url.split('?')[0];
      if (baseUrl.includes('/view')) {
        embedUrl = `${baseUrl}?embed`;
      } else {
        const match = baseUrl.match(/design\/([^\/]+)\//);
        if (match && match[1]) {
           embedUrl = `https://www.canva.com/design/${match[1]}/view?embed`;
        } else {
           embedUrl = `${baseUrl}/view?embed`;
        }
      }
    }

    return embedUrl;
  };

  return (
    <div className="space-y-4 md:space-y-8 animate-in fade-in duration-700 text-black pb-20">

      {/* Search & Filter */}
      <section className="bg-white p-6 md:p-8 rounded-3xl md:rounded-[3rem] border border-slate-100 shadow-sm space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
          <div className="space-y-1">
            <h3 className="text-xl md:text-2xl font-black text-slate-800 tracking-tight">Perpustakaan Digital</h3>
            <p className="text-slate-500 font-medium text-xs">Materi belajar terpadu untuk semua mata pelajaran.</p>
          </div>
          <div className="relative w-full md:w-96 group">
            <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 w-5 h-5 group-focus-within:text-indigo-500 transition-colors" />
            <input 
              type="text" 
              placeholder="Cari materi..." 
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-14 pr-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold outline-none focus:ring-4 focus:ring-indigo-500/5 transition-all text-sm shadow-inner"
            />
          </div>
        </div>

        <div className="flex flex-col md:flex-row gap-6">
           {/* Subject Filter */}
           <div className="space-y-3 flex-1">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Pilih Mata Pelajaran</p>
              <div className="flex flex-wrap gap-2">
                <button
                  onClick={() => setSubjectFilter('all')}
                  className={`px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                    subjectFilter === 'all' ? 'bg-indigo-600 text-white shadow-lg' : 'bg-slate-50 text-slate-400 border border-slate-100 hover:bg-slate-100'
                  }`}
                >
                  Semua Mapel
                </button>
                {subjects.map(sub => (
                  <button
                    key={sub}
                    onClick={() => setSubjectFilter(sub)}
                    className={`px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                      subjectFilter === sub ? 'bg-indigo-600 text-white shadow-lg' : 'bg-slate-50 text-slate-400 border border-slate-100 hover:bg-slate-100'
                    }`}
                  >
                    {sub}
                  </button>
                ))}
              </div>
           </div>

           {/* Type Filter */}
           <div className="space-y-3">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Format Konten</p>
              <div className="flex flex-wrap gap-2">
                {['all', 'embed', 'file', 'link'].map((f) => (
                  <button
                    key={f}
                    onClick={() => setActiveFilter(f)}
                    className={`px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                      activeFilter === f ? 'bg-slate-900 text-white shadow-lg' : 'bg-slate-50 text-slate-400 border border-slate-100 hover:bg-slate-100'
                    }`}
                  >
                    {f === 'all' ? 'Semua Format' : f === 'embed' ? 'Video' : f === 'file' ? 'Modul' : 'Tautan'}
                  </button>
                ))}
              </div>
           </div>
        </div>
      </section>

      {/* Materials Grid */}
      <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {filteredMaterials.map((m: any) => {
          const style = getTypeStyle(m.type);
          const Icon = style.icon;
          return (
            <div key={m.id} className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm hover:shadow-2xl hover:-translate-y-2 transition-all duration-500 group flex flex-col overflow-hidden relative">
              <div className={`h-28 ${style.bg} relative flex items-center justify-center overflow-hidden`}>
                <Icon size={48} className={`${style.text} opacity-10 group-hover:scale-125 transition-transform duration-700`} />
                <div className="absolute top-4 left-4">
                   <span className="px-3 py-1 bg-white/90 backdrop-blur-sm text-[8px] font-black text-slate-800 uppercase tracking-widest rounded-lg shadow-sm">
                      {m.subject}
                   </span>
                </div>
              </div>
              <div className="p-7 flex-1 flex flex-col">
                <span className={`text-[8px] font-black uppercase tracking-widest px-2.5 py-1 ${style.bg} ${style.text} rounded-lg w-fit mb-4`}>
                  {style.label}
                </span>
                <h4 className="text-lg font-black text-slate-800 mb-2 leading-tight group-hover:text-indigo-600 transition-colors line-clamp-2">{m.title}</h4>
                <p className="text-xs text-slate-500 font-medium mb-6 line-clamp-2 leading-relaxed">{m.description || 'Klik untuk membuka modul pengajaran.'}</p>
                <button 
                  onClick={() => setSelectedMaterial(m)}
                  className="mt-auto w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-600 transition-all flex items-center justify-center gap-3 shadow-xl active:scale-95"
                >
                  Buka Materi <ChevronRight size={16}/>
                </button>
              </div>
            </div>
          );
        })}

        {filteredMaterials.length === 0 && (
           <div className="col-span-full py-24 text-center bg-white rounded-[3rem] border-2 border-dashed border-slate-100">
              <SearchX size={48} className="mx-auto text-slate-200 mb-4" />
              <p className="text-slate-400 font-black text-xs uppercase tracking-widest">Tidak ada materi yang ditemukan.</p>
           </div>
        )}
      </section>

      {/* Embed Modal */}
      {selectedMaterial && (() => {
        const style = getTypeStyle(selectedMaterial.type);
        const Icon = style.icon;
        return (
          <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-md z-[100] flex items-center justify-center p-4 md:p-8 animate-in fade-in duration-300">
            <div className="bg-white w-full max-w-6xl h-full md:max-h-[90vh] rounded-[3rem] shadow-2xl flex flex-col overflow-hidden">
              <div className="p-6 md:px-10 border-b border-slate-50 flex items-center justify-between bg-white shrink-0">
                 <div className="flex items-center gap-4">
                    <div className={`w-14 h-14 rounded-2xl flex items-center justify-center ${style.bg} ${style.text} shadow-inner`}>
                      <Icon size={28} />
                    </div>
                    <div className="min-w-0">
