              >Semua</button>
              {subjects.map(sub => (
                <button 
                  key={sub}
                  onClick={() => setSubjectFilter(sub)}
                  className={`px-4 py-2 rounded-lg text-[10px] font-black uppercase transition-all ${subjectFilter === sub ? 'bg-indigo-600 text-white' : 'bg-slate-50 text-slate-400'}`}
                >{sub}</button>
              ))}
           </div>
        </div>
