import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Home, BookOpen, ClipboardList, CheckCircle, Settings, Loader2 } from 'lucide-react';
import Layout from '../components/Layout';
import { User, SiteSettings } from '../types';
import { db } from '../App';

import HomeTab from './student/HomeTab.tsx';
import MaterialsTab from './student/MaterialsTab.tsx';
import TasksTab from './student/TasksTab.tsx';
import GradesTab from './student/GradesTab.tsx';
import SettingsTab from './student/SettingsTab.tsx';

interface StudentDashboardProps {
  user: User;
  onLogout: () => void;
  settings: SiteSettings;
  onUpdateUser?: (u: User) => void;
}

const StudentDashboard: React.FC<StudentDashboardProps> = ({ user, onLogout, settings, onUpdateUser }) => {
  const [activeView, setActiveView] = useState('home');
  const [materials, setMaterials] = useState<any[]>([]);
  const [tasks, setTasks] = useState<any[]>([]);
  const [submissions, setSubmissions] = useState<any[]>([]);
  const [notifications, setNotifications] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  // State untuk menyimpan filter mapel yang dipicu dari klik kartu di HomeTab
  const [selectedSubjectFilter, setSelectedSubjectFilter] = useState('all');

  const fetchData = useCallback(async () => {
    if (!user.id) return;

    try {
      const [storedMaterials, storedTasks, storedSubmissions, storedNotifs] = await Promise.all([
        db.get('elearning_materials'),
        db.get('elearning_tasks'),
        db.getByQuery('elearning_submissions', 'studentId', user.id),
        db.getByQuery('elearning_notifications', 'userId', user.id)
      ]);

      setMaterials(Array.isArray(storedMaterials) ? storedMaterials : []);
      setTasks(Array.isArray(storedTasks) ? storedTasks : []);
      setSubmissions(Array.isArray(storedSubmissions) ? storedSubmissions : []);
      setNotifications(Array.isArray(storedNotifs) ? storedNotifs : []);
    } catch (err) {
      console.error("Gagal sinkronisasi data siswa:", err);
    } finally {
      setLoading(false);
    }
  }, [user.id]);

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 30000); 
    return () => clearInterval(interval);
  }, [fetchData]);

  // Fungsi wrapper untuk navigasi dari Sidebar
  const handleSidebarNavigate = (view: string) => {
    // Jika navigasi lewat sidebar ke Materi Belajar, reset filter ke 'all'
    if (view === 'materials') {
      setSelectedSubjectFilter('all');
    }
    setActiveView(view);
  };

  const handleMarkAsRead = async (id: string) => {
    const notif = notifications.find(n => n.id === id);
    if (notif) {
      await db.update('elearning_notifications', id, { ...notif, read: true });
      setNotifications(notifications.map(n => n.id === id ? { ...n, read: true } : n));
    }
  };

  const handleMarkAllRead = async () => {
    const unreadIds = notifications.filter(n => !n.read).map(n => n.id);
    if (unreadIds.length === 0) return;

    try {
      const updated = notifications.map(n => ({ ...n, read: true }));
      setNotifications(updated);
      await db.saveAll('elearning_notifications', updated);
    } catch (err) {
      console.error("Gagal menandai semua terbaca:", err);
    }
  };

  const ensureArray = (data: any): string[] => {
    if (Array.isArray(data)) return data;
    if (typeof data === 'string') return data.split(',').filter(Boolean);
    return [];
  };

  const studentMaterials = useMemo(() => materials.filter(m => ensureArray(m.targetClassIds).includes(user.classId || '')), [materials, user.classId]);
  const studentTasks = useMemo(() => tasks.filter(t => ensureArray(t.targetClassIds).includes(user.classId || '')), [tasks, user.classId]);
  const studentSubmissions = useMemo(() => submissions, [submissions]); 

  const renderContent = () => {
    switch (activeView) {
      case 'home': 
        return <HomeTab 
          user={user} 
          materials={studentMaterials} 
          tasks={studentTasks} 
          submissions={studentSubmissions} 
          setActiveView={setActiveView} 
          setSelectedSubjectFilter={setSelectedSubjectFilter}
        />;
      case 'materials': 
        return <MaterialsTab materials={studentMaterials} initialSubject={selectedSubjectFilter} />;
      case 'tasks': 
        return <TasksTab user={user} tasks={studentTasks} submissions={studentSubmissions} onRefresh={fetchData} />;
      case 'grades': 
        return <GradesTab tasks={tasks} submissions={studentSubmissions} />;
      case 'settings': 
        return <SettingsTab user={user} onUpdateUser={onUpdateUser} />;
      default: 
        return <HomeTab user={user} materials={studentMaterials} tasks={studentTasks} submissions={studentSubmissions} setActiveView={setActiveView} />;
    }
  };

  return (
    <Layout 
      user={user} 
      onLogout={onLogout} 
      sidebarItems={[
        { id: 'home', label: 'Beranda', icon: Home },
        { id: 'materials', label: 'Materi Belajar', icon: BookOpen },
        { id: 'tasks', label: 'Tugas Saya', icon: ClipboardList },
        { id: 'grades', label: 'Nilai & Hasil', icon: CheckCircle },
        { id: 'settings', label: 'Pengaturan', icon: Settings },
      ]} 
      activeView={activeView} 
      setActiveView={handleSidebarNavigate}
      logoUrl={settings.logoUrl}
      siteName={settings.siteName}
      notifications={notifications}
      onMarkAsRead={handleMarkAsRead}
      onMarkAllAsRead={handleMarkAllRead}
    >
      {loading ? (
        <div className="flex flex-col items-center justify-center py-32 gap-4">
          <Loader2 className="animate-spin text-emerald-600" size={48} />
          <p className="text-slate-400 font-black text-[10px] uppercase tracking-widest">Memuat Data Belajar...</p>
        </div>
      ) : renderContent()}
    </Layout>
  );
};

export default StudentDashboard;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  FileText, ExternalLink, Search, Filter, 
  PlayCircle, Link as LinkIcon, Clock, Sparkles, 
  SearchX, ChevronRight, BookOpen, X, Info,
  Monitor, Globe, ArrowUpRight, Zap, CheckCircle2
} from 'lucide-react';

interface MaterialsTabProps {
  materials: any[];
  initialSubject?: string;
}

const MaterialsTab: React.FC<MaterialsTabProps> = ({ materials, initialSubject }) => {
  const [search, setSearch] = useState('');
  const [activeFilter, setActiveFilter] = useState('all');
  const [subjectFilter, setSubjectFilter] = useState(initialSubject || 'all');
  const [selectedMaterial, setSelectedMaterial] = useState<any | null>(null);

  // Ambil daftar mata pelajaran unik dari materi yang tersedia
  const subjects = useMemo(() => {
    return Array.from(new Set(materials.map(m => m.subject))).filter(Boolean);
  }, [materials]);

  // Efek untuk menangani filter otomatis saat navigasi dari Home atau Sidebar
  useEffect(() => {
    if (initialSubject) {
      setSubjectFilter(initialSubject);
    }
  }, [initialSubject]);

  const filteredMaterials = useMemo(() => {
    return materials.filter(m => {
      const matchSearch = (m.title || '').toLowerCase().includes(search.toLowerCase()) || 
                          (m.description || '').toLowerCase().includes(search.toLowerCase());
      const matchType = activeFilter === 'all' || m.type === activeFilter;
      const matchSubject = subjectFilter === 'all' || m.subject === subjectFilter;
      return matchSearch && matchType && matchSubject;
    });
  }, [materials, search, activeFilter, subjectFilter]);

  const getTypeStyle = (type: string) => {
    switch(type) {
      case 'embed': return { bg: 'bg-purple-50', text: 'text-purple-600', icon: PlayCircle, label: 'Video' };
      case 'file': return { bg: 'bg-emerald-50', text: 'text-emerald-600', icon: FileText, label: 'Modul' };
      case 'link': return { bg: 'bg-blue-50', text: 'text-blue-600', icon: LinkIcon, label: 'Tautan' };
      default: return { bg: 'bg-slate-50', text: 'text-slate-600', icon: BookOpen, label: 'Materi' };
    }
  };

  const getEmbedUrl = (url: string) => {
    if (!url) return '';
    let embedUrl = url;
    if (url.includes('youtube.com/watch?v=')) {
      embedUrl = url.replace('watch?v=', 'embed/');
    } else if (url.includes('youtu.be/')) {
      embedUrl = 'https://www.youtube.com/embed/' + url.split('youtu.be/')[1];
    } else if (url.includes('docs.google.com')) {
      embedUrl = url.includes('?') ? `${url}&embedded=true` : `${url}?embedded=true`;
    } else if (url.includes('canva.com/design/')) {
      const baseUrl = url.split('?')[0];
      embedUrl = baseUrl.includes('/view') ? `${baseUrl}?embed` : `${baseUrl}/view?embed`;
    }
    return embedUrl;
  };

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-700 text-black pb-24 max-w-[1600px] mx-auto">

